INSERT INTO `departamento_pessoal_cargo` (`id`, `nome`, `descricao`, `cbo`, `ativo`, `filial_id`) VALUES (4, 'Coordenador de Planejamento', 'O Técnico de Planejamento e Programação da Manutenção planeja, programa e controla os serviços de manutenção preventiva, preditiva e corretiva de máquinas, equipamentos e instalações relacionadas à produção industrial. Propõe melhorias para aumentar a produtividade da produção, por meio da manutenção produtiva. Trata e disponibiliza as informações do setor de manutenção industrial. Cumpre normas técnicas e de qualidade, procedimentos da empresa e normas regulamentadoras de saúde e segurança no trabalho e de preservação ambiental.', '391130', 1, 2);
