INSERT INTO `departamento_pessoal_cargo` (`id`, `nome`, `descricao`, `cbo`, `ativo`, `filial_id`) VALUES (60, 'Coordenador', 'Fazer a gestão técnica da equipe de manutenção (orientar, acompanhar e fiscalizar e os serviços pertinentes ao contrato de manutenção); interagir com os clientes através de reuniões e visitas e elaborar relatórios técnicos.', '1427-05', 1, 1);
INSERT INTO `departamento_pessoal_cargo` (`id`, `nome`, `descricao`, `cbo`, `ativo`, `filial_id`) VALUES (61, 'Tecnico Mecânico de Refrigeração Senior', 'Realizar os serviços de manutenção preventiva e corretiva dos equipamentos de ar condicionado, ventilação e exaustão; eventualmente executar serviços de solda oxiacetilenica; preenchimento das ordens de serviços pertinentes.', '9501-10', 1, 1);
INSERT INTO `departamento_pessoal_cargo` (`id`, `nome`, `descricao`, `cbo`, `ativo`, `filial_id`) VALUES (62, 'Analista de departamento Pessoal', 'Rotinas Operacionais: Admissão, rescisão, controle de ponto, férias e benefícios. \r\neSocial e Obrigações: Apoio no envio de informações ao eSocial e obrigações acessórias (SEFIP, RAIS, etc.).\r\nConhecimento: Legislação trabalhista básica e Excel intermediário. Nível: Geralmente exige ensino superior cursando ou completo', '2524-05', 1, 1);
