INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (1, 'definicoes', '', 'RISCOS AMBIENTAIS\nSão aqueles proporcionados pelos agentes físicos, químicos, biológicos, ergonômicos ou de acidentes que quando presentes no ambiente de trabalho, os quais, em razão de sua natureza, intensidade, concentração e tempo de exposição podem causar danos à saúde e integridade física dos trabalhadores expostos.\n\nAGENTES FÍSICOS\nSão todas as formas de energia capaz de se propagar nos ambientes e atingir os trabalhadores, podendo causar danos à saúde ou à integridade física dos mesmos, tais como: calor, frio, ruído, vibração, radiação ionizante, radiação não ionizante, pressões anormais e umidade.\n\nAGENTES QUÍMICOS\nSão substâncias ou produtos de origens orgânicas ou minerais, naturais ou artificiais, geradas e dispersas nos ambientes pelas mais variadas fontes, que podem penetrar no organismo dos trabalhadores por inalação, absorção cutânea ou ingestão, e causar danos à saúde e/ou integridade física dos mesmos.\n\nAGENTES BIOLÓGICOS\nSão todos os vírus, bactérias, protozoários, fungos, parasitas ou bacilos, que podem penetrar no organismo dos trabalhadores por meio do aparelho respiratório, contato com a pele, trato digestivo e que podem causar danos à saúde dos trabalhadores.\n\nAGENTES ERGONÔMICOS\nConsideram-se agentes ergonômicos todos os fatores que possam interferir nas características psicofisiológicas do trabalhador, causando desconforto ou afetando sua saúde, tais como: trabalho físico pesado; posturas incorretas; posições incômodas; repetitividade, monotonia; ritmo excessivo; trabalho em turnos e trabalho noturno; jornada de trabalho.\n\nAGENTES MECÂNICOS OU RISCOS DE ACIDENTES\nConsideram-se agentes mecânicos ou riscos de acidente as diversas situações do ambiente de trabalho que têm potencial de causar danos instantâneos, materiais ou pessoais, aos quais os trabalhadores estão expostos.\n\nEPI - EQUIPAMENTO DE PROTEÇÃO INDIVIDUAL\nÉ todo meio ou dispositivo de uso exclusivamente pessoal, destinado a neutralizar, preservar e proteger a saúde e/ou a integridade física dos trabalhadores.\n\nEPC - EQUIPAMENTO DE PROTEÇÃO COLETIVA\nTodo e qualquer equipamento utilizado para eliminar ou neutralizar os agentes agressivos ao meio laboral, visando a preservação da saúde e/ou integridade física dos trabalhadores.\n\nPERIGO\nFonte ou situação ou ato potencial com capacidade de gerar dano ou perturbação funcional no ser humano.\n\nRISCO\nCombinação da Probabilidade e da Severidade da Consequência (Impacto) de um evento.\n\nLIMITE DE TOLERÂNCIA\nConcentração ou intensidade máxima ou mínima, relacionada com a natureza e o tempo de exposição ao agente, que não causará danos à saúde do trabalhador, durante sua vida laboral.\n\nGRUPO HOMOGÊNEO DE EXPOSIÇÃO (GHE)\nGrupo formado por trabalhadores que experimentam ou estão expostos a um mesmo agente.\n\nGRUPO DE EXPOSIÇÃO SIMILAR (GES)\nGrupo formado por trabalhadores que desenvolvem uma atividade especial, não rotineira e que em realizando-as experimentam ou ficam expostas a um determinado agente.', 10, 1, '2026-02-16 18:42:28.634217', '2026-02-16 18:42:28.634265', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (2, 'desenvolvimento', '', 'a) Antecipação: Análise prévia de projetos, de instalações, de processos e de métodos de trabalho, ou modificações nos mesmos, visando identificar os possíveis riscos.\n\nb) Reconhecimento dos Riscos: Aplicação das Ordens de Serviço de Segurança (OSS) conforme NR-1 a fim de divulgar e antecipar a neutralização ou eliminação de atitudes e/ou condições de riscos ambientais e de acidentes nas áreas de trabalho.\n\nc) Avaliação: As avaliações dos agentes físicos, químicos, biológicos e ergonômicos nas áreas de trabalho serão realizadas, quando necessário ou durante a revisão do Programa.', 20, 1, '2026-02-16 18:42:28.711921', '2026-02-16 18:42:28.711938', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (3, 'divulgacao', '', 'Os documentos e os procedimentos operacionais que integram o Programa de Gerenciamento de Risco (PGR) estarão disponíveis aos empregados.\n\nA atualização do PGR será realizada quando da ocorrência de alterações significativas de ordem tecnológica, operacional, legal ou regulatória que provoquem a necessidade de adequação dos documentos que o integram ou ainda quando for recomendado na auditoria anual.\n\nCabe aos responsáveis pelas respectivas áreas procederem a divulgação das atualizações dos documentos que integram o PGR, após as devidas aprovações, respeitadas eventuais restrições para o manuseio e circulação quando se tratarem de documentos controlados.\n\nEsses dados foram levantados por profissionais do departamento de QHSE (Qualidade, Saúde, Segurança e Meio Ambiente) com a participação dos responsáveis pelas áreas analisadas, designados de CIPA e dos próprios trabalhadores e inseridos no Inventário de Riscos deste PGR.', 30, 1, '2026-02-16 18:42:28.786170', '2026-02-16 18:42:28.786189', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (4, 'documento_base', '', 'Este Programa de Gerenciamento de Riscos foi elaborado de acordo com os requisitos da Norma Regulamentadora (NR) 1, com redação dada pela Portaria SEPRT nº 6.730, de 09/03/2020, publicada no Diário Oficial da União de 12/03/2020.\n\nTodos os requisitos da NR 01 foram cumpridos neste PGR, sendo que destacamos alguns para fins ilustrativos:\n\nA organização deve implementar, por estabelecimento, o gerenciamento de riscos ocupacionais em suas atividades.\n\nOs documentos integrantes do PGR devem ser elaborados sob a responsabilidade da organização, respeitado o disposto nas demais Normas Regulamentadoras, datados e assinados, assim como devem estar sempre disponíveis aos trabalhadores interessados ou seus representantes e à Inspeção do Trabalho.', 40, 1, '2026-02-16 18:42:28.858721', '2026-02-16 18:42:28.858741', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (5, 'documento_base_metas', '', 'A organização deve implementar, por estabelecimento, o gerenciamento de riscos ocupacionais em suas atividades mantendo o ambiente de trabalho dentro de condições adequadas ao desenvolvimento das atividades laborais de todos os trabalhadores da empresa, eliminando ou minimizando os riscos existentes a níveis compatíveis com os limites de tolerância da NR-15 da Portaria 3.214/78 do Ministério do Trabalho ou na ausência destes os valores limites de exposição ocupacional adotados pela ACGIH (American Conference of Governmental Industrial Hygienists) através de um gerenciamento de riscos ocupacionais que deve constituir um Programa de Gerenciamento de Riscos - PGR.', 50, 1, '2026-02-16 18:42:28.931731', '2026-02-16 18:42:28.931758', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (6, 'documento_base_objetivo', '', 'O PGR é um documento que tem como finalidade antecipar, reconhecer e avaliar os riscos físicos, químicos, biológicos, ergonômicos e de acidentes, buscar melhoria contínua na mitigação e na eliminação de fatores que podem trazer prejuízos à saúde e segurança do trabalhador garantindo a implantação de medidas de controle quando necessárias.\n\nManter a equipe, permanentemente, bem preparada para a realização dos trabalhos seguindo procedimentos que previnam a ocorrência de acidentes e danos à sua saúde.', 60, 1, '2026-02-16 18:42:29.036544', '2026-02-16 18:42:29.036564', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (7, 'estrutura_estrategia', '', 'O PGR está estruturado em cinco fases distintas:\n\n1) A primeira fase trata da elaboração do documento base onde está contemplado os tópicos básicos da estrutura do programa de gerenciamento de risco;\n2) Na segunda fase é a realização da análise preliminar de perigos e sua inserção na planilha de inventário de riscos, perigos, aspectos e impactos;\n3) A terceira é realização de avaliação quantitativa (quando houver necessidade) para os itens avaliados no levantamento preliminar de perigo considerando uma avaliação qualitativa;\n4) A quarta fase é a realização da construção do cronograma de ação com todas as partes envolvidas para o estabelecimento do Plano de Ação;\n5) Por fim, a execução do plano de ação, com a implementação de todo o planejado incluindo os programas complementares de atendimento a NRs especificas e seus desdobramentos.', 70, 1, '2026-02-16 18:42:29.109852', '2026-02-16 18:42:29.109873', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (8, 'estrutura_periodicidade', '', 'Faz-se necessário 01 (uma) vez a cada 02 (dois) anos deverá ser realizada uma análise global do PGR, para avaliação do seu desenvolvimento e ajustes, estabelecendo novas metas e prioridades, exceto quando na ocorrência das seguintes situações:\n\na) Após implementação das medidas de prevenção, para avaliação de riscos residuais;\nb) Após inovações e modificações nas tecnologias, ambientes, processos, condições, procedimentos e organização do trabalho que impliquem em novos riscos ou modifiquem os riscos existentes;\nc) Quando identificadas inadequações, insuficiências ou ineficácias das medidas de prevenção;\nd) Na ocorrência de acidentes ou doenças relacionadas ao trabalho;\ne) Quando houver mudança nos requisitos legais aplicáveis.', 80, 1, '2026-02-16 18:42:29.183200', '2026-02-16 18:42:29.183230', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (9, 'estrutura_pgr', '', '', 90, 1, '2026-02-16 18:42:29.258967', '2026-02-16 18:42:29.258984', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (10, 'estrutura_requisitos', '', 'Sempre discutir com os empregados da {empresa} os assuntos pertinentes ao PGR.\n\nÉ Obrigação Legal por parte da empresa a elaboração do Programa de Gerenciamento de Risco – PGR – visando preservar a saúde e integridade física dos trabalhadores.\n\nA concepção do PGR atende as exigências da NR 09 relativas à avaliação e controle de fatores de riscos ambientais de natureza química, física ou biológica. Contempla também as exigências da NR 15.', 100, 1, '2026-02-16 18:42:29.333823', '2026-02-16 18:42:29.333847', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (11, 'legislacao', '', 'Além de atender a Portaria SEPRT n° 6730 de 09 de março de 2020, o PGR atende uma série de outras normas e legislações complementares:\n\n- PORTARIA 3214/78 – NORMAS REGULAMENTADORAS\n- NORMAS DE HIGIENE OCUPACIONAL – FUNDACENTRO\n- ABNT ISO NBR 45001 – SISTEMA DE GESTÃO DE SEGURANÇA E SAÚDE OCUPACIONAL\n- ABNT ISO NBR 31000 – GESTÃO DE RISCOS – DIRETRIZES\n- ABNT NBR 5413 – ILUMINAÇÃO DE INTERIORES\n- ABNT NBR 10152 – NÍVEL DE RUÍDO PARA CONFORTO ACÚSTICO', 110, 1, '2026-02-16 18:42:29.407495', '2026-02-16 18:42:29.407518', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (12, 'medidas_epc', '', '{empresa} faz uso de suas normas e seus procedimentos para orientar, treinar e capacitar os funcionários quanto às medidas de controle coletivos que proporcionam maior segurança na execução de suas tarefas.', 120, 1, '2026-02-16 18:42:29.483208', '2026-02-16 18:42:29.483234', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (13, 'medidas_epi', '', '{empresa} faz uso de suas normas e seus procedimentos para orientar, treinar e capacitar os funcionários quanto às medidas de ordem individuais (EPI) que proporcionam maior segurança na execução de suas tarefas.\n\nQuando comprovadas a inviabilidade técnica ou econômica para a implementação da proteção coletiva, a empresa fornecerá EPI conforme procedimentos específicos para as áreas envolvidas.', 130, 1, '2026-02-16 18:42:29.560955', '2026-02-16 18:42:29.560997', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (14, 'medidas_protecao', '', '', 140, 1, '2026-02-16 18:42:29.637530', '2026-02-16 18:42:29.637570', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (15, 'metodo_calor', '', 'A Norma Regulamentadora 15 (NR 15), em seu Anexo 3, especifica algumas condições em que o ambiente, exposto ao calor, é considerado acima da tolerância para a saúde do trabalhador. A medição de níveis de calor e temperatura, é através do IBUTG (Índice de Bulbo Úmido Termômetro de Globo).', 150, 1, '2026-02-16 18:42:29.713514', '2026-02-16 18:42:29.713558', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (16, 'metodo_quimico', '', 'Inventário de agentes Químicos, utilizando as Fichas de Informação de Produtos Químicos (FISPQ) fornecida pelo fabricante do produto, com critérios estabelecidos pelos anexos 11 e 13 da NR 15 da Portaria 3214/78.', 160, 1, '2026-02-16 18:42:29.791483', '2026-02-16 18:42:29.791528', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (17, 'metodo_ruido', '', 'Conforme estabelece a Norma NHO 01 da Fundacentro, Normas Técnicas ANSI 4-1983 e IEC 651-79 e Anexo 1 da NR 15 da Portaria 3214/78, o agente ruído será avaliado por Dosimetria inicial na elaboração do PGR ou quando houver mudanças significativas no ambiente de trabalho.', 170, 1, '2026-02-16 18:42:29.866189', '2026-02-16 18:42:29.866229', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (18, 'metodologia_avaliacao', '', 'O PGR é parte integrante do conjunto mais amplo das iniciativas da empresa no campo da preservação da saúde e integridade dos trabalhadores, devendo estar articulado com o disposto nas demais NRs. Em especial com o Programa de Controle Médico de Saúde Ocupacional - PCMSO, determinado de acordo com a NR - 7.', 180, 1, '2026-02-16 18:42:29.943974', '2026-02-16 18:42:29.944016', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (19, 'plano_acao', '', 'No Programa Gerenciamento de Riscos – PGR serão observadas e seguidas as seguintes etapas no plano de ação:\n\na) Antecipação e Reconhecimento dos riscos;\nb) Estabelecimento de prioridades e metas de avaliação e controle;\nc) Avaliação dos riscos e da exposição dos trabalhadores;\nd) Implantação de medidas de controle e avaliação de sua eficácia;\ne) Monitoramento da exposição aos riscos;\nf) Registro e divulgação de dados através de treinamentos;\ng) Prevenção, eliminação ou redução de agentes prejudiciais à saúde.', 190, 1, '2026-02-16 18:42:30.022260', '2026-02-16 18:42:30.022307', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (20, 'recomendacoes', '', '- Aplicação de medidas, sempre que necessárias, de caráter administrativo ou da organização do trabalho.\n- Aplicação de Treinamento de Segurança em geral, sobre Uso de EPI, Cuidados com produtos de químicos, Levantamento de peso e Trabalho em Altura, assim como outros treinamentos que se fizerem necessários;\n- Aplicação de Treinamento para membro designado de segurança da CIPA, no setor, em cumprimento com a portaria 3214 de 08/06/78 – NR 05;\n- Dotação de creme protetor para as mãos para os funcionários que tiverem contato direto com graxas, óleos e outros produtos químicos durante a jornada de trabalho;\n- Fornecimento de EPIs adequados de acordo com Ficha Técnica de Classificação de EPI por Função;\n- Orientações sobre o uso correto e higiênico dos vestiários e asseio pessoal;\n- Execução do Gerenciamento de Riscos através da observação de segurança e uso dos EPIs;\n- Guarda de documentação do controle das intervenções de segurança do trabalho;\n- Aplicação de rígido controle médico dos empregados.', 200, 1, '2026-02-16 18:42:30.099385', '2026-02-16 18:42:30.099430', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (21, 'resp_empregados', '', 'a) Colaborar e participar da implantação e execução do PGR;\nb) Seguir as orientações recebidas nos treinamentos do PGR;\nc) Informar à chefia ocorrências que a seu julgamento ofereçam riscos ambientais;\nd) Cumprir as disposições legais e regulamentares sobre segurança e saúde no trabalho;\ne) Submeter-se aos exames médicos previstos nas NR;\nf) Em caso de acidente de trabalho, informar à supervisão;\ng) Colaborar com a organização na aplicação das NR;\nh) Usar o equipamento de proteção individual (EPI) fornecido pelo empregador.', 210, 1, '2026-02-16 18:42:30.177344', '2026-02-16 18:42:30.177389', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (22, 'resp_organizacao', '', 'a) Evitar os riscos ocupacionais que possam ser originados no trabalho;\nb) Identificar os perigos e possíveis lesões ou agravos à saúde;\nc) Avaliar os riscos ocupacionais indicando o nível de risco;\nd) Classificar os riscos ocupacionais para determinar a necessidade de adoção de medidas de prevenção;\ne) Implementar medidas de prevenção, de acordo com a classificação de risco e na ordem de prioridade estabelecida;\nf) Acompanhar o controle dos riscos ocupacionais;\ng) A organização deve adotar as medidas necessárias para melhorar o desempenho em SST;\nh) Realizar a avaliação de riscos ocupacionais;\ni) A organização deve avaliar os riscos ocupacionais relativos aos perigos identificados em seu(s) estabelecimento(s).', 220, 1, '2026-02-16 18:42:30.253821', '2026-02-16 18:42:30.253866', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (23, 'responsabilidades', '', '', 230, 1, '2026-02-16 18:42:30.331643', '2026-02-16 18:42:30.331686', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (24, 'cronograma_acoes', '', 'O cronograma de ações abaixo apresenta as atividades necessárias para o cumprimento do PGR, com seus respectivos públicos alvo, periodicidade de realização e próxima avaliação/revisão prevista.\n\nCM = contrato de manutenção\n\n*** O cronograma detalhado é gerado automaticamente a partir dos dados cadastrados no sistema (model CronogramaAcaoPGR). ***', 10, 1, '2026-03-01 17:29:33.014468', '2026-03-01 17:29:33.014521', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (25, 'diretrizes', '', '', 40, 1, '2026-03-01 17:29:33.158314', '2026-03-01 17:29:33.158362', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (26, 'diretrizes_estrategia', '', 'DIREÇÃO\nEste PGR está sendo elaborado pela área de Segurança do Trabalho da {empresa} e com apoio operacional para implantação.\n\nCOLABORADORES\nTodos os empregados em todos os cargos devem colaborar e participar de forma efetiva dentro de seu setor de trabalho, com informações, para que este Programa alcance seus objetivos.\n\nRECURSOS\nDeverão ser disponibilizados recursos humanos, materiais e financeiros, para a elaboração e execução do "Programa"; das medidas de controle, dos monitoramentos e das atualizações permanentes, conforme exigência Legal do Ministério do Trabalho e Emprego.', 50, 1, '2026-03-01 17:29:33.286914', '2026-03-01 17:29:33.286963', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (27, 'estrutura_eficacia', '', 'A análise da eficácia e as correções das metas e prioridades serão realizadas, considerando as avaliações do ambiente de trabalho, os dados coletados com os trabalhadores e a verificação de possíveis alterações nos setores de trabalho. O cronograma de ações será alterado conforme as correções das metas e prioridades estabelecidas.\n\nEste Documento Base, será apresentado em reunião de Designados CIPA, ficando a disposição para consultas dos trabalhadores e órgãos oficiais de fiscalização.', 100, 1, '2026-03-01 17:29:33.488397', '2026-03-01 17:29:33.488438', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (28, 'estrutura_implantacao', '', 'O Plano de ação com seu cronograma será apresentado às Hierarquias superiores, à Designados CIPA e os registros das ações serão mantidos em arquivo sob responsabilidade do funcionário responsável pela Segurança do Trabalho, por período de 20 anos, fazendo divulgação das soluções propostas, através dos meios de comunicação existentes na empresa.', 120, 1, '2026-03-01 17:29:33.605017', '2026-03-01 17:29:33.605066', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (29, 'estrutura_registro', '', 'Este Documento Base, será apresentado aos Designados CIPA, ficando a disposição para consultas dos trabalhadores e órgãos oficiais de fiscalização.', 150, 1, '2026-03-01 17:29:33.769365', '2026-03-01 17:29:33.769413', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (30, 'inventario_excecoes', '', 'Ruído – se as exposições forem superiores ao limite de tolerância ou nível de ação, mas as condições se mantiverem constantes e o controle for baseado apenas no uso de equipamento de proteção individual avaliado como eficaz, a periodicidade do monitoramento poderá ser reduzida a critério do avaliador.\n\nTambém a critério do avaliador a periodicidade do monitoramento para outras exposições poderá ser reduzida se as condições de trabalho forem estáveis e a incerteza das avaliações for baixa, exceto se houver exigência legal em contrário.', 170, 1, '2026-03-01 17:29:33.889509', '2026-03-01 17:29:33.889555', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (31, 'inventario_riscos_intro', '', 'RISCOS AMBIENTAIS E OCUPACIONAIS\n\nDurante as avaliações serão considerados os seguintes aspectos:', 180, 1, '2026-03-01 17:29:33.988359', '2026-03-01 17:29:33.988379', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (32, 'inventario_tab_acoes_mitigacao', '', 'Serão priorizadas as medidas de controle coletivo dos agentes nocivos à Segurança e Saúde dos Trabalhadores de acordo com a seguinte ordem abaixo.\n\nPriorização | Medida | Significado | Descrição | Redução do Risco\n1° | E - Eliminação | Eliminação total da fonte de risco | 100%\n2° | S - Substituição ou Minimização | Substituição de matérias-primas, equipamentos e procedimento de trabalho | 40%\n3° | CE - Controle de Engenharia | Enclausuramento, adaptação do ambiente de trabalho, automatização do processo e etc. | 25%\n4° | CA - Controle Administrativo | Sinalização, treinamentos, exames médicos, implementação de procedimento de segurança e etc. | 15%\n5° | DP - Dispositivo de Proteção | Uso de EPIs e implementação de EPCs | 10%\n\nQuando, em qualquer fase do Programa, os riscos detectados ultrapassarem os valores limites das normas utilizadas, serão adotadas medidas de controle, com o objetivo de eliminar ou reduzir a exposição ao risco.\n\nSituações de risco grave e iminente serão comunicados ao supervisor da área, que deverá tomar medidas para eliminação do agente causador, sob risco de interdição do local.', 190, 1, '2026-03-01 17:29:34.082735', '2026-03-01 17:29:34.082780', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (33, 'inventario_tab_exposicao', '', 'Para a gradação da exposição ao dano potencial (efeito crítico) atribui-se um índice de exposição (E) variando de 1 a 5 conforme os critérios da Tabela 3.\n\nEXPOSIÇÃO (E)\nNível | Classificação | Descrição\n1 | ESPORÁDICA | Exposição acontece pelo menos uma vez por ano por um período curto de tempo ou nunca acontece\n2 | POUCO FREQUENTE | Exposição acontece algumas vezes por mês\n3 | OCASIONAL | Exposição acontece várias vezes por semana ou várias vezes por dia por períodos curtos (< 60 min.)\n4 | FREQUENTE | Exposição ocorre várias vezes por dia por períodos não prolongados (< 120 min. seguidos)\n5 | CONTÍNUA | Exposição por períodos diários ou várias vezes por dia por períodos prolongados (> 120 min. seguidos)', 200, 1, '2026-03-01 17:29:34.181665', '2026-03-01 17:29:34.181728', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (34, 'inventario_tab_gravidade', '', 'Para a gradação da gravidade do dano potencial (efeito crítico) atribui-se um índice de gravidade (G) variando de 1 a 5 conforme os critérios da tabela abaixo.\n\nGRAVIDADE (G)\nNível | Classificação | Descrição\n1 | NEGLIGENCIÁVEL | Danos pessoais ligeiros ou sem danos, mal-estar passageiro, pequenas lesões sem qualquer tipo de incapacidade. (Sem baixa)\n2 | MARGINAL | Danos ou doenças ocupacionais menores com ou sem incapacidade temporária sem assistência médica especializada, primeiro socorro. (Lesões ou doenças até 10 dias de baixa)\n3 | MODERADO | Danos ou doenças ocupacionais de média gravidade, requerendo assistência médica e baixa com duração superior a 10 dias. (Lesões ou doenças suscetíveis de provocar baixa de duração compreendida entre 11 e 60 dias)\n4 | GRAVE | Danos ou doenças ocupacionais graves, lesões com incapacidade temporária ou parcial permanente, internamento hospitalar. (Incapacidade parcial permanente, ou lesões ou doenças suscetíveis de provocar baixa de duração superior a 60 dias)\n5 | CRÍTICO | Morte ou incapacidade total permanente', 210, 1, '2026-03-01 17:29:34.282128', '2026-03-01 17:29:34.282177', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (35, 'inventario_tab_matriz_risco', '', 'MATRIZ SEVERIDADE (S) x PROBABILIDADE (P) → CLASSIFICAÇÃO DO RISCO\n\n         |  S=A  |  S=B  |  S=C  |  S=D  |  S=E\nP=1      |   B   |   B   |   B   |   T   |   T\nP=2      |   B   |   B   |   T   |   M   |   M\nP=3      |   B   |   T   |   M   |   M   |   S\nP=4      |   T   |   M   |   M   |   S   |   S\nP=5      |   T   |   M   |   S   |   S   |   S\n\nLegenda: B = Baixo | T = Tolerável | M = Moderado | S = Significativo\n\nCaso a tabela 7 indique que para determinado risco não é necessário realizar uma ação específica, mas a empresa venha a receber uma autuação de organismo fiscalizador, ou venha acontecer algum acidente em decorrência do perigo relacionado ao risco, deve-se realizar alguma ação para minimizar esse risco, independente do resultado obtido na tabela.\n\nO plano de ação deve ser amplo e deve atender as reais necessidades de melhoria da empresa, não se prendendo somente as exigências da NR 01.', 220, 1, '2026-03-01 17:29:34.382410', '2026-03-01 17:29:34.382458', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (36, 'inventario_tab_matriz_severidade', '', 'Estimar e definir a categoria de cada risco, a partir da combinação dos valores atribuídos para exposição (E) e gravidade (G) do dano, utilizando a matriz apresentada na Tabela 4.\n\nMATRIZ GRAVIDADE (G) x EXPOSIÇÃO (E) → SEVERIDADE\n\n         |  G=1  |  G=2  |  G=3  |  G=4  |  G=5\nE=1      |   A   |   A   |   A   |   B   |   B\nE=2      |   A   |   B   |   B   |   C   |   D\nE=3      |   A   |   B   |   C   |   D   |   D\nE=4      |   B   |   C   |   D   |   E   |   E\nE=5      |   B   |   D   |   D   |   E   |   E', 230, 1, '2026-03-01 17:29:34.482220', '2026-03-01 17:29:34.482262', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (37, 'inventario_tab_priorizacao', '', 'Para priorização das ações será avaliado a Severidade (S) após a verificação das medidas de controle adotadas, juntamente com o grau de Probabilidade (P).\n\nRISCO (R)\nClassificação do Risco | Prazo para Ações\nBaixo | Aceitável\nTolerável | < 01 (um) ano\nModerado | < 06 (seis) meses\nSignificativo | Paralização\n\nSe o risco for considerado aceitável, não será necessário adotar ações de mitigação do risco.', 240, 1, '2026-03-01 17:29:34.582841', '2026-03-01 17:29:34.582890', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (38, 'inventario_tab_probabilidade', '', 'Conceito que caracteriza a chance de que o perigo se concretize, ou seja, a probabilidade de consequência prejudicial ao ser humano ou a empresa, caso permita-se que as condições inseguras persistam.\n\nPROBABILIDADE (P)\nNível | Classificação | Descrição | Frequência\n1 | IMPROVÁVEL | Probabilidade de 1 ocorrência até uma vez em cada 50 anos | (P ≤ 1 ocorrência/50 anos)\n2 | REMOTO | Probabilidade de 1 ocorrência em cada 5 anos | (1 ocorrência/50 anos < P ≤ 1 ocorrência/5 anos)\n3 | OCASIONAL | Probabilidade de 1 ocorrência em cada ano | (1 ocorrência/5 anos < P ≤ 1 ocorrência/ano)\n4 | PROVÁVEL | Probabilidade de 1 ocorrência em cada mês | (1 ocorrência/ano < P ≤ 1 ocorrência/mês)\n5 | FREQUENTE | Probabilidade de ocorrência mais do que uma vez por mês | (P > 1 ocorrência/mês)\n\nOBSERVAÇÃO\nSe a exposição a contaminantes atmosféricos ou ao ruído for avaliada como excessiva, ou seja, maior que o limite de exposição permitido, ou acima do nível de ação, deve-se definir o índice de probabilidade de ocorrência do dano estimado como 1, 2, 3, 4 ou 5 por julgamento profissional do avaliador, conforme o grau de adequação do EPI ao tipo de exposição, sua manutenção e uso efetivo.', 250, 1, '2026-03-01 17:29:34.683860', '2026-03-01 17:29:34.683894', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (39, 'inventario_tab_severidade', '', 'SEVERIDADE (S)\nNível | Classificação\nA | NEGLIGENCIÁVEL\nB | MARGINAL\nC | GRAVE\nD | MUITO GRAVE\nE | CRÍTICO', 260, 1, '2026-03-01 17:29:34.782601', '2026-03-01 17:29:34.782634', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (40, 'medidas_administrativas', '', 'A {empresa} possui procedimentos de segurança e saúde ocupacional, que são repassados para os funcionários através de treinamentos e material de informações contendo todas as normas da empresa no que diz respeito à segurança e saúde ocupacional.\n\nOs funcionários recebem uma ordem de serviço (OSS) contendo suas obrigações no que diz respeito à segurança e saúde, assim como as penalidades pelo descumprimento das normas de segurança impostas pela legislação vigente, pela {empresa} e pelo Cliente.', 280, 1, '2026-03-01 17:29:34.897734', '2026-03-01 17:29:34.897786', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (41, 'medidas_monitoramento', '', 'Todas as medidas de controle, existentes ou implantadas, serão avaliadas periodicamente, tendo como base as avaliações ambientais e o PCMSO.\n\nO PGR também será avaliado periodicamente, em concordância com o cronograma implantado e por período nunca superior a 2 (dois) anos.', 310, 1, '2026-03-01 17:29:35.035385', '2026-03-01 17:29:35.035418', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (42, 'medidas_protecao_geral', '', 'a) Medidas que eliminam ou reduzam a utilização ou a formação de agentes prejudiciais à saúde;\nb) Medidas que previnem a liberação ou disseminação desses agentes no ambiente de trabalho;\nc) Medidas que reduzem os níveis ou a concentração desses agentes nos ambientes de trabalho;\nd) Medidas de caráter administrativo ou de organização do trabalho;\ne) Medidas de ordem individual (Equipamento de Proteção Individual – EPI):\nf) Seleção do EPI adequado tecnicamente ao risco a que o trabalhador está exposto e a atividade exercida;\ng) Programa de treinamento dos trabalhadores quanto a sua correta utilização e orientação sobre as limitações de proteção que o EPI oferece;\nh) Critérios e mecanismos de avaliação da eficácia das medidas de proteção, conforme análise e dados do PCMSO.', 330, 1, '2026-03-01 17:29:35.150518', '2026-03-01 17:29:35.150551', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (43, 'medidas_recomendacao_epi', '', 'Deverá ser utilizada a "Ficha de Controle de EPIs – Equipamentos de Proteção Individual", conforme determinação de ordem legal, para registro de 1ª (primeira) dotação e substituição dos EPIs (Equipamentos de Proteção Individual) quando necessário, em função dos riscos existentes no ambiente de trabalho.\n\nCONSOLIDAÇÃO DAS LEIS DO TRABALHO – CLT\nArt. 158 – Cabe aos empregados:\nI – Observar as normas de segurança e medicina do trabalho, inclusive as instruções de que trata o item II do artigo anterior;\nII – Colaborar com a empresa na aplicação dos dispositivos deste capítulo.\n\nParágrafo Único: Constitui ato faltoso do empregado a recusa injustificada:\na) ...\nb) ao uso dos equipamentos de proteção individual fornecidos pela empresa.', 340, 1, '2026-03-01 17:29:35.246559', '2026-03-01 17:29:35.246581', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (44, 'medidas_registro_divulgacao', '', 'O registro e a divulgação de dados são estruturados de forma a constituir um histórico técnico e administrativo do desenvolvimento do Programa.\n\nOs dados serão mantidos por um período mínimo de 20 (vinte) anos. O registro de dados estará sempre disponível aos trabalhadores interessados ou de seus representantes legais e para as autoridades competentes.', 350, 1, '2026-03-01 17:29:35.341354', '2026-03-01 17:29:35.341384', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (45, 'medidas_substituicao_epi', '', 'É responsabilidade do empregado, comunicar a sua gerência imediata, sobre qualquer alteração no EPI que o torne impróprio para uso, além da perda ou extravio do equipamento solicitando sua reposição. No caso de EPI impróprio para uso, o mesmo deverá ser devolvido na ocasião de sua reposição, para posterior descarte.', 360, 1, '2026-03-01 17:29:35.435390', '2026-03-01 17:29:35.435415', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (46, 'medidas_uso_epi', '', 'O EPI deve ser utilizado apenas para a finalidade a que se destina e guardado com o próprio usuário. Sua conservação deve ser realizada conforme treinamento aplicado pela {empresa} ou instruções de uso definidas pelo fabricante.\n\nA {empresa} não realiza e nem solicita aos fabricantes readequação de EPI. O EPI quando apresenta algum tipo de problema é imediatamente substituído. Em caso de C.A vencido a {empresa} entra em contato com o fornecedor para verificar a possibilidade de troca do mesmo, ou o fornecimento de documento de solicitação de renovação do C.A junto ao MTE, quando vencido o prazo de validade estipulado pelo órgão nacional competente em matéria de segurança e saúde do trabalho. Quando nenhuma dessas opções for obtida o EPI deverá ser substituído.\n\nA {empresa} não realiza higienização do EPI, eles são simplesmente substituídos.\n\nCabe ao colaborador quanto ao EPI:\na) Usar o EPI apenas para a finalidade a que se destina;\nb) responsabilizar-se pela guarda e conservação;\nc) comunicar ao empregador qualquer alteração que o torne impróprio para uso;\nd) cumprir as determinações do empregador sobre o uso adequado.', 370, 1, '2026-03-01 17:29:35.530298', '2026-03-01 17:29:35.530319', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (47, 'metodo_biologico', '', 'Consideram-se agentes biológicos as bactérias, fungos, bacilos, parasitas, protozoários, vírus, microrganismos, entre outros, e a avaliação será qualitativa, com base no serviço prestado.', 380, 1, '2026-03-01 17:29:35.625512', '2026-03-01 17:29:35.625532', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (48, 'metodo_ergonomico', '', 'Relatório de Avaliação de Condições Ergonômicas, conforme NR 17 da Portaria 3214/78, será realizado anualmente, ou quando houver mudanças significativas no ambiente de trabalho.', 400, 1, '2026-03-01 17:29:35.739938', '2026-03-01 17:29:35.739958', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (49, 'metodo_mecanico', '', 'Por se tratar de risco de acidente sua metodologia e caracterização passa pela utilização da ferramenta Análise Preliminar de Risco – APR, e considera as situações que envolvam acidentes do tipo mecânico advindo de atividades "braçais", de organização e distribuição de layout, atividades especificas que envolvam risco de movimentação manual de peças ou equipamentos, bem como a movimentação do trabalhador dentro da empresa, trabalhos em altura e trabalhos com eletricidade.', 410, 1, '2026-03-01 17:29:35.833872', '2026-03-01 17:29:35.833892', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (50, 'plano_acao_documentacao', '', 'O PGR deve conter, no mínimo, os seguintes documentos:\na) inventário de riscos;\nb) plano de ação.\n\nComo metodologia de execução do plano de ação, estabeleceu o método 5 porquês como ferramenta para construção objetiva das soluções que serão implantadas neste PGR, desta forma o gerenciamento dos riscos ocupacionais poderá estar detalhado neste documento e seu resumo controlado pela planilha GRO.\n\nAs metodologias de investigação vão auxiliar no mapeamento e na padronização de processos de análise de riscos, cumprindo suas etapas a indefinição dará lugar à produtividade na resolução dos problemas (perigos) detectados no inventário de perigos, riscos, aspectos e impactos tendo em vista que todos os envolvidos têm o conhecimento exato de o que fazer, quando, onde, de que forma, porquê, etc.\n\nComo resultado, além do ganho de produtividade, constrói-se sinergia que, hoje em dia é extremamente importante para construção de um diferencial estratégico para qualquer negócio.', 460, 1, '2026-03-01 17:29:36.035414', '2026-03-01 17:29:36.035453', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (51, 'resp_cipa', '', 'a) Conhecer o PGR da Empresa e relacionar-se com a Engenharia de Segurança do Trabalho, no sentido de participar das ações de prevenção dos infortúnios e doenças do trabalho junto aos empregados, como também no controle das ações de segurança programadas na Empresa.\nb) O representante designado pela {empresa}, devidamente treinado, irá atuar na coordenação de todas as atividades relativas à Segurança e Saúde.', 480, 1, '2026-03-01 17:29:36.180391', '2026-03-01 17:29:36.180413', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (52, 'resp_informacao', '', 'a) Consultar os trabalhadores quanto à percepção de riscos ocupacionais, podendo para este fim ser adotadas as manifestações da Comissão Interna de Prevenção de Acidentes - CIPA, quando houver; e\nb) Comunicar aos trabalhadores sobre os riscos consolidados no inventário de riscos e as medidas de prevenção do plano de ação do PGR.', 500, 1, '2026-03-01 17:29:36.325134', '2026-03-01 17:29:36.325168', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (53, 'resp_medicina', '', 'a) Informar, ao responsável pelo PGR, as alterações biológicas ocorridas com os empregados;\nb) Contribuir com as informações técnicas sobre os riscos à saúde, que podem ser causados pelos agentes de risco;\nc) Desenvolver o PCMSO.', 510, 1, '2026-03-01 17:29:36.422069', '2026-03-01 17:29:36.422091', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (54, 'resp_procedimentos', '', 'a) Cabe a Alta Direção e superiores hierárquicos: Apoiar a implantação, manutenção e desenvolvimento do PGR e das atividades prevencionistas e efetivar normas, instruções e programas estabelecidos pelo Ministério do Trabalho e Emprego.\nb) Desenvolver, administrar e inspecionar as atividades de prevenção de acidentes, cumprindo os dispositivos legais vigentes.\nc) Orientar e assessorar os diversos órgãos da Empresa de forma a garantir o desempenho dos mesmos, na aplicação dos programas de segurança estabelecidos.\nd) Elaborar e propor normas, instruções e regulamentos de Segurança e Higiene do Trabalho.\ne) Manter, obrigatoriamente, programa de inspeção de segurança visando levantar os riscos de acidentes.\nf) Investigar os acidentes, elaborar e colocar em prática os procedimentos específicos, incluindo atribuições a todos que possam vir a participar nas investigações.\ng) Manter registros de acidentes e todos os detalhes necessários aos estudos estatísticos e funcionais, da prevenção de acidentes.\nh) Elaborar programas e ministrar treinamento geral e específico, de segurança e medicina do trabalho e promover campanhas internas de prevenção de acidentes e higiene do trabalho.', 530, 1, '2026-03-01 17:29:36.534667', '2026-03-01 17:29:36.534688', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (55, 'resp_seguranca', '', 'a) Elaborar, estabelecer, implantar, assegurar a manutenção do programa, acompanhar e monitorar, bem como promover o comprometimento, envolvimento, treinamentos sobre a importância do programa e oferecer suporte técnico, de acordo com a solicitação da empresa.', 540, 1, '2026-03-01 17:29:36.632135', '2026-03-01 17:29:36.632153', 1);
INSERT INTO `pgr_secao_texto` (`id`, `secao`, `titulo_customizado`, `conteudo`, `ordem`, `incluir_no_pdf`, `criado_em`, `atualizado_em`, `pgr_documento_id`) VALUES (56, 'resp_supervisao', '', 'a) Colaborar em todas as ações que se fizerem necessárias à implantação do programa e promover a motivação de todas as pessoas da unidade a que pertence;\nb) Informar aos trabalhadores de maneira apropriada e suficiente, sobre os riscos ambientais que possam existir nos locais de trabalho e sobre os meios disponíveis para prevenir ou limitar a ação dos mesmos.\nc) Cumprir e fazer cumprir as disposições legais e regulamentares sobre segurança e saúde no trabalho;\nd) Informar aos trabalhadores, quanto aos riscos existentes no local de trabalho e medidas prevenção adotadas para eliminação de riscos;\ne) Inspecionar, permanentemente, as operações, equipamentos, máquinas e edificações, em suas áreas de atuação, visando eliminar riscos de acidentes.\nf) Permitir que representantes dos trabalhadores acompanhem a fiscalização dos preceitos legais e regulamentares sobre segurança e saúde no trabalho;\ng) Determinar procedimentos que devem ser adotados em caso de acidente ou doença relacionada ao trabalho, incluindo a análise de suas causas;\nh) Disponibilizar à Inspeção do Trabalho todas as informações relativas à segurança e saúde no trabalho;\ni) Implementar medidas de prevenção, ouvidos os trabalhadores, de acordo com a seguinte ordem de prioridade;\nj) Eliminação dos fatores de risco;\nk) Informar à administração a ocorrência de acidentes do trabalho quando houver;\nl) Minimização e controle dos fatores de risco, com a adoção de medidas administrativas ou de organização do trabalho.', 550, 1, '2026-03-01 17:29:36.729910', '2026-03-01 17:29:36.729929', 1);
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (1, 'documento_base', '2. DOCUMENTO BASE', 'PGR – PROGRAMA DE GERENCIAMENTO DE RISCOS\n\nEste Programa de Gerenciamento de Riscos foi elaborado de acordo com os requisitos da Norma Regulamentadora (NR) 1, com redação dada pela Portaria SEPRT nº 6.730, de 09/03/2020, publicada no Diário Oficial da União de 12/03/2020.\n\nTodos os requisitos da NR 01 foram cumpridos neste PGR, sendo que destacamos alguns para fins ilustrativos:\n\nA organização deve implementar, por estabelecimento, o gerenciamento de riscos ocupacionais em suas atividades.\n\nOs documentos integrantes do PGR devem ser elaborados sob a responsabilidade da organização, respeitado o disposto nas demais Normas Regulamentadoras, datados e assinados, assim como devem estar sempre disponíveis aos trabalhadores interessados ou seus representantes e à Inspeção do Trabalho.', 1, '2026-02-16 17:51:58.100664', '2026-02-28 21:57:30.931632');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (2, 'documento_base_metas', 'METAS', 'A organização deve implementar, por estabelecimento, o gerenciamento de riscos ocupacionais em suas atividades mantendo o ambiente de trabalho dentro de condições adequadas ao desenvolvimento das atividades laborais de todos os trabalhadores da empresa, eliminando ou minimizando os riscos existentes a níveis compatíveis com os limites de tolerância da NR-15 da Portaria 3.214/78 do Ministério do Trabalho ou na ausência destes os valores limites de exposição ocupacional adotados pela ACGIH (American Conference of Governmental Industrial Hygienists) através de um gerenciamento de riscos ocupacionais que deve constituir um Programa de Gerenciamento de Riscos - PGR.', 1, '2026-02-16 17:51:58.220830', '2026-02-28 21:57:31.019176');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (3, 'documento_base_objetivo', 'OBJETIVO GERAL', 'O PGR é um documento que tem como finalidade antecipar, reconhecer e avaliar os riscos físicos, químicos, biológicos, ergonômicos e de acidentes, buscar melhoria contínua na mitigação e na eliminação de fatores que podem trazer prejuízos à saúde e segurança do trabalhador garantindo a implantação de medidas de controle quando necessárias.\n\nManter a equipe, permanentemente, bem preparada para a realização dos trabalhos seguindo procedimentos que previnam a ocorrência de acidentes e danos à sua saúde.', 1, '2026-02-16 17:51:58.341211', '2026-02-28 21:57:31.123131');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (4, 'definicoes', '3. DEFINIÇÕES', 'RISCOS AMBIENTAIS\nSão aqueles proporcionados pelos agentes físicos, químicos, biológicos, ergonômicos ou de acidentes que quando presentes no ambiente de trabalho, os quais, em razão de sua natureza, intensidade, concentração e tempo de exposição podem causar danos à saúde e integridade física dos trabalhadores expostos.\n\nAGENTES FÍSICOS\nSão todas as formas de energia capaz de se propagar nos ambientes e atingir os trabalhadores, podendo causar danos à saúde ou à integridade física dos mesmos, tais como: calor, frio, ruído, vibração, radiação ionizante, radiação não ionizante, pressões anormais e umidade.\n\nAGENTES QUÍMICOS\nSão substâncias ou produtos de origens orgânicas ou minerais, naturais ou artificiais, geradas e dispersas nos ambientes pelas mais variadas fontes, que podem penetrar no organismo dos trabalhadores por inalação, absorção cutânea ou ingestão, e causar danos à saúde e/ou integridade física dos mesmos, sob a forma de poeiras, névoas, gases, vapores ou outras substâncias, compostas ou produtos químicos em geral.\n\nAGENTES BIOLÓGICOS\nSão todos os vírus, bactérias, protozoários, fungos, parasitas ou bacilos, que podem penetrar no organismo dos trabalhadores por meio do aparelho respiratório, contato com a pele, trato digestivo e que podem causar danos à saúde dos trabalhadores.\n\nAGENTES ERGONÔMICOS\nConsideram-se agentes ergonômicos todos os fatores que possam interferir nas características psicofisiológicas do trabalhador, causando desconforto ou afetando sua saúde, tais como: trabalho físico pesado; posturas incorretas; posições incômodas; repetitividade, monotonia; ritmo excessivo; trabalho em turnos e trabalho noturno; jornada de trabalho.\n\nAGENTES MECÂNICOS OU RISCOS DE ACIDENTES\nConsideram-se agentes mecânicos ou riscos de acidente as diversas situações do ambiente de trabalho que têm potencial de causar danos instantâneos, materiais ou pessoais, aos quais os trabalhadores estão expostos, como por exemplo: as máquinas e equipamentos sem proteção, probabilidade de incêndio e explosão, arranjo físico inadequado, armazenamento inadequado, ferramentas inadequadas ou defeituosas; iluminação inadequada; contato com eletricidade; animais peçonhentos; entre outros.\n\nEPI - EQUIPAMENTO DE PROTEÇÃO INDIVIDUAL\nÉ todo meio ou dispositivo de uso exclusivamente pessoal, destinado a neutralizar, preservar e proteger a saúde e/ou a integridade física dos trabalhadores.\n\nEPC - EQUIPAMENTO DE PROTEÇÃO COLETIVA\nTodo e qualquer equipamento utilizado para eliminar ou neutralizar os agentes agressivos ao meio laboral, visando a preservação da saúde e/ou integridade física dos trabalhadores.\n\nANÁLISE QUALITATIVA\nDeterminação nas atividades, através de inspeção dos locais de trabalho constante nos anexos 7, 8, 9, 10 e 13 da NR-15. A Análise Qualitativa também indicará a necessidade técnica de avaliações quantitativas dos GHEs expostos a agentes ambientais quantificáveis, sendo seus resultados comparados com os limites de tolerância oficialmente estabelecidos.\n\nAVALIAÇÃO QUANTITATIVA\nDeterminação nas atividades que se desenvolvem com o objetivo de:\na) comprovar o controle da exposição ou a inexistência dos riscos identificados na etapa de reconhecimento;\nb) dimensionar a exposição dos trabalhadores;\nc) subsidiar o equacionamento das medidas de controle.\n\nPERIGO\nFonte ou situação ou ato potencial com capacidade de gerar dano ou perturbação funcional no ser humano, ou ainda, originem de situações que podem culminar com incidentes no produto ou processo dentro da empresa. Dentro deste entendimento consideramos sua natureza com física, química, biológica, ergonômica e de acidentes diretos ou indiretos.\n\nIDENTIFICAÇÃO DE PERIGOS\nProcesso analítico de reconhecimento utilizando-se de ferramenta técnica Inventário de riscos, perigos, aspectos e impactos, cuja finalidade é registrar sua existência, bem como definir suas características.\n\nRISCO\nCombinação da Probabilidade e da Severidade da Consequência (Impacto) de um evento; a ocorrência de um evento perigoso ou a exposição com a gravidade da lesão, doença ou dano ao patrimônio que pode ser causado por um evento imponderável, imprevisto.\n\nCLASSIFICAÇÃO DE RISCOS\nProcesso no qual estima-se a magnitude do Risco, considerando em decisão se este é Baixo, Tolerável, Moderado ou Significativo; Avaliação de Risco proveniente de perigos.\n\nACIDENTE\nÉ uma ocorrência que resultou em lesão, doença, fatalidade, prejuízo ao processo produtivo, perda de matéria prima (produto) ou ainda dano ao meio ambiente.\n\nINCIDENTE\nEvento ou ocorrência que poderia vir a acontecer no decorrer do processo produtivo relacionado ao trabalho podendo gerar lesão, doença, fatalidade ou perda dentro do processo produtivo.\n\nLIMITE DE TOLERÂNCIA\nConcentração ou intensidade máxima ou mínima, relacionada com a natureza e o tempo de exposição ao agente, que não causará danos à saúde do trabalhador, durante sua vida laboral.\n\nLIMITE DE EXPOSIÇÃO\nConcentração da média ponderada pelo tempo para uma jornada de 8 horas diárias e 44 horas semanais, para a qual a maioria dos trabalhadores pode estar repetidamente exposta, dia após dia, sem sofrer efeitos adversos à sua saúde.\n\nLIMITE DE EXPOSIÇÃO – CURTA DURAÇÃO\nConcentração Máxima a que os trabalhadores podem estar expostos continuamente por um período curto, de até 15 minutos, sem sofrer irritação, lesão tissular crônica ou irreversível, narcose em grau suficiente para aumentar a predisposição a acidentes, impedir auto salvamento ou reduzir significativamente a eficiência no trabalho, desde que não sejam permitidas mais de 4 exposições diárias, com pelo menos 60 minutos de intervalo entre os períodos de exposição.\n\nNÍVEL DE AÇÃO\nValor acima do qual devem ser iniciadas as ações preventivas (Monitoramento periódicos, Informação aos Trabalhadores e o Controle Médico), de forma a minimizar a probabilidade de que as exposições a agentes ambientais ultrapassem os limites de exposição.\n\nGRUPO HOMOGÊNEO DE EXPOSIÇÃO (GHE)\nGrupo formado por trabalhadores que experimentam ou estão expostos a um mesmo agente, permitindo desta forma que seja feita apenas uma avaliação individual de exposição à agentes ambientais agressivos no ambiente de trabalho que é possível aplicá-la para todo o grupo. Isso não implica em concluir que todos eles necessitem sofrer idênticas exposições num mesmo dia. Como decorrência da aplicação dos fundamentos em que se baseia a estatística, como ciência, um pequeno número de amostras selecionadas randomicamente, ou seja, aleatoriamente, pode ser utilizado para determinar as distribuições de exposição dentro de um GHE. Escolher o parâmetro, que servirá como base para estruturação do GHE. Normalmente a escolha recairá sobre um dos parâmetros a seguir:\n• Tarefas dos trabalhadores;\n• Funções/atividades;\n• Agentes ambientais.\n\nGRUPO DE EXPOSIÇÃO SIMILAR (GES)\nGrupo formado por trabalhadores que desenvolvem uma atividade especial, não rotineira e que em realizando-as experimentam ou ficam expostas a um determinado agente, não existente em sua atividade rotineira.', 1, '2026-02-16 17:51:58.457414', '2026-02-28 21:57:31.237817');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (5, 'estrutura_pgr', '4. ESTRUTURA DO PGR', '', 1, '2026-02-16 17:51:58.577542', '2026-02-28 21:57:31.347180');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (6, 'estrutura_requisitos', 'REQUISITOS LEGAIS', 'Sempre discutir com os empregados da {empresa} os assuntos pertinentes ao PGR.\n\nÉ Obrigação Legal por parte da empresa a elaboração do Programa de Gerenciamento de Risco – PGR – visando preservar a saúde e integridade física dos trabalhadores.\n\nA concepção do PGR atende as exigências da NR 09 relativas à avaliação e controle de fatores de riscos ambientais de natureza química, física ou biológica. Contempla também as exigências da NR 15. De acordo com a NR 09, NR 15 e limites da ACGIH, são considerados riscos inaceitáveis aqueles cujas exposições ultrapassarem os limites exposição ocupacionais estabelecidos. Entretanto, ações devem ser tomadas quando a exposição estimada ultrapassar o nível de ação que, segundo a NR-09, para agentes químicos corresponde à metade do limite de exposição ocupacional, e para o ruído, a dose de 0,5 (dose superior a 50%). Essas ações não se restringem apenas à modificação das medidas de controle, mas inclui também a pesquisa aprofundada das fontes geradoras, o monitoramento mais frequente da exposição e a intensificação da vigilância médica, com atenção especial para identificação de efeitos precoces.\n\nSegundo o critério legal podem ser considerados aceitáveis riscos relacionados a exposições acima dos limites permitidos quando os trabalhadores utilizarem proteção individual adequada, com garantia de manutenção e comprovação de eficácia e eficiência de uso dos mesmos.\n\nOs critérios legais serão utilizados para demonstrar que a {empresa} atende os requisitos legais, buscando-se adotar critérios complementares e voluntários para reduzir as exposições e garantir uma qualidade adequada dos ambientes de trabalho.', 1, '2026-02-16 17:51:58.697528', '2026-02-28 21:57:31.458390');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (7, 'estrutura_estrategia', 'ESTRATÉGIA E METODOLOGIA DE AÇÃO', 'O PGR está estruturado em cinco fases distintas:\n\n1) A primeira fase trata da elaboração do documento base onde está contemplado os tópicos básicos da estrutura do programa de gerenciamento de risco;\n2) Na segunda fase é a realização da análise preliminar de perigos e sua inserção na planilha de inventário de riscos, perigos, aspectos e impactos;\n3) A terceira é realização de avaliação quantitativa (quando houver necessidade) para os itens avaliados no levantamento preliminar de perigo considerando uma avaliação qualitativa;\n4) A quarta fase é a realização da construção do cronograma de ação com todas as partes envolvidas para o estabelecimento do Plano de Ação;\n5) Por fim, a execução do plano de ação, com a implementação de todo o planejado incluindo os programas complementares de atendimento a NRs especificas e seus desdobramentos.', 1, '2026-02-16 17:51:58.818215', '2026-02-28 21:57:31.565747');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (8, 'estrutura_periodicidade', 'PERIODICIDADE E FORMA DE AVALIAÇÃO DO DESENVOLVIMENTO DO PGR', 'Faz-se necessário 01 (uma) vez a cada 02 (dois) anos deverá ser realizada uma análise global do PGR, para avaliação do seu desenvolvimento e ajustes, estabelecendo novas metas e prioridades, exceto quando na ocorrência das seguintes situações:\n\na) Após implementação das medidas de prevenção, para avaliação de riscos residuais;\nb) Após inovações e modificações nas tecnologias, ambientes, processos, condições, procedimentos e organização do trabalho que impliquem em novos riscos ou modifiquem os riscos existentes;\nc) Quando identificadas inadequações, insuficiências ou ineficácias das medidas de prevenção;\nd) Na ocorrência de acidentes ou doenças relacionadas ao trabalho;\ne) Quando houver mudança nos requisitos legais aplicáveis.', 1, '2026-02-16 17:51:58.934955', '2026-02-28 21:57:31.824210');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (9, 'responsabilidades', '5. DEFINIÇÃO DAS RESPONSABILIDADES', '', 1, '2026-02-16 17:51:59.053549', '2026-02-28 21:57:32.210030');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (10, 'resp_organizacao', 'DA ORGANIZAÇÃO', 'a) Evitar os riscos ocupacionais que possam ser originados no trabalho;\nb) Identificar os perigos e possíveis lesões ou agravos à saúde;\nc) Avaliar os riscos ocupacionais indicando o nível de risco;\nd) Classificar os riscos ocupacionais para determinar a necessidade de adoção de medidas de prevenção;\ne) Implementar medidas de prevenção, de acordo com a classificação de risco e na ordem de prioridade estabelecida na tabela 6; e\nf) Acompanhar o controle dos riscos ocupacionais.\ng) A organização deve adotar as medidas necessárias para melhorar o desempenho em SST.\nh) Realizar a avaliação de riscos ocupacionais.\ni) A organização deve avaliar os riscos ocupacionais relativos aos perigos identificados em seu(s) estabelecimento(s), de forma a manter informações para adoção de medidas de prevenção.', 1, '2026-02-16 17:51:59.187377', '2026-02-28 21:57:32.326031');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (11, 'resp_empregados', 'DOS EMPREGADOS', 'a) Colaborar e participar da implantação e execução do PGR;\nb) Seguir as orientações recebidas nos treinamentos do PGR, que participar;\nc) Informar à chefia ocorrências que a seu julgamento ofereçam riscos ambientais.\nd) Cumprir as disposições legais e regulamentares sobre segurança e saúde no trabalho, inclusive as ordens de serviço expedidas pelo empregador;\ne) Submeter-se aos exames médicos previstos nas NR;\nf) Em caso de acidente de trabalho, informar à supervisão;\ng) Colaborar com a organização na aplicação das NR;\nh) Usar o equipamento de proteção individual (EPI) fornecido pelo empregador.', 1, '2026-02-16 17:51:59.333432', '2026-02-28 21:57:33.149961');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (12, 'desenvolvimento', '7. DESENVOLVIMENTO DO PGR', 'ETAPAS\n\na) Antecipação:\nAnálise prévia de projetos, de instalações, de processos e de métodos de trabalho, ou modificações nos mesmos, visando identificar os possíveis riscos, propor e introduzir medidas para a sua redução ou eliminação.\n\nb) Reconhecimento dos Riscos:\nAplicação das Ordens de Serviço de Segurança (OSS) conforme NR-1 a fim de divulgar e antecipar a neutralização ou eliminação de atitudes e/ou condições de riscos ambientais e de acidentes nas áreas de trabalho. Complementação com realização de Análise Preliminar de Risco (APR), somente quando necessário.\n\nRealização de Inspeções nos locais de trabalho para avaliação dos riscos e de entrevistas com os empregados para obter as seguintes informações:\n- Identificação;\n- Fontes geradoras;\n- Trajetórias e meio de propagação dos agentes;\n- Identificação das funções e número de trabalhadores expostos aos riscos com a realização do Grupo de exposição similar (GES);\n- Caracterização da atividade e do tipo de exposição;\n- Dados possíveis de comprometimentos à saúde no trabalho;\n- Possíveis danos à saúde, conforme literatura técnica;\n- Descrição das medidas de controle já existente.\n\nPara cada GES então é realizada a identificação dos perigos levando em conta as atividades, máquinas equipamentos, ferramentas, toxicidade dos produtos químicos que utilizam, agentes e perigos presentes e a eficácia das medidas de proteção existentes, verificação das condições sanitárias, de iluminação, ventilação e estado de conservação. Em seguida realiza-se a avaliação qualitativa dos riscos e a priorização de ações e/ou avaliações necessárias ao seu controle.\n\nc) Avaliação:\nAs avaliações dos agentes físicos, químicos, biológicos e ergonômicos nas áreas de trabalho serão realizadas, quando necessário ou durante a revisão do "Programa".', 1, '2026-02-16 17:51:59.450341', '2026-02-28 21:57:33.483744');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (13, 'metodologia_avaliacao', '8. METODOLOGIA DE AVALIAÇÃO', 'O PGR é parte integrante do conjunto mais amplo das iniciativas da empresa no campo da preservação da saúde e integridade dos trabalhadores, devendo estar articulado com o disposto nas demais NR\'s. Em especial com o Programa de Controle Médico de Saúde Ocupacional - PCMSO, determinado de acordo com a NR - 7, promovendo assim uma interligação entre os programas prevencionistas da empresa.', 1, '2026-02-16 17:51:59.592384', '2026-02-28 21:57:33.576998');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (14, 'metodo_ruido', 'AGENTE FÍSICO RUÍDO', 'Conforme estabelece a Norma NHO 01 da Fundacentro, Normas Técnicas ANSI 4-1983 e IEC 651-79 e Anexo 1 da NR 15 da Portaria 3214/78, o agente ruído será avaliado por Dosimetria inicial na elaboração do PGR ou quando houver mudanças significativas no ambiente de trabalho.', 1, '2026-02-16 17:51:59.739277', '2026-02-28 21:57:33.667228');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (15, 'metodo_calor', 'AGENTE FÍSICO CALOR', 'A Norma Regulamentadora 15 (NR 15), em seu Anexo 3, especifica algumas condições em que o ambiente, exposto ao calor, é considerado acima da tolerância para a saúde do trabalhador. A medição de níveis de calor e temperatura, é através do IBUTG (Índice de Bulbo Úmido Termômetro de Globo), que são calculados através de medidores de stress térmico.', 1, '2026-02-16 17:51:59.857132', '2026-02-28 21:57:33.757785');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (16, 'metodo_quimico', 'AGENTES QUÍMICOS', 'Inventário de agentes Químicos, utilizando as Fichas de Informação de Produtos Químicos (FISPQ) fornecida pelo fabricante do produto, com critérios estabelecidos pelos anexos 11 e 13 da NR 15 da Portaria 3214/78.', 1, '2026-02-16 17:51:59.992363', '2026-02-28 21:57:33.847867');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (17, 'medidas_protecao', '11. MEDIDAS DE PROTEÇÃO', '', 1, '2026-02-16 17:52:00.108086', '2026-02-28 21:57:35.940711');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (18, 'medidas_epc', 'MEDIDAS DE PROTEÇÃO COLETIVA', 'A {empresa} faz uso de suas normas e seus procedimentos para orientar, treinar e capacitar os funcionários quanto às medidas de controle coletivos que proporcionam maior segurança na execução de suas tarefas. Através destes treinamentos e procedimentos os funcionários recebem orientações diversas tais como:\n\na) Sinalizar à área para a execução da tarefa de forma segura tanto para os envolvidos diretos quanto indiretos, com a utilização de cones, fita zebrada, placas de informações, colete refletivo, alerta sonoro e iluminação.\nb) Fazer uso de sistemas de bloqueio de fontes hidráulicas, mecânicas, elétricas e outras fontes geradoras de riscos.\nc) Os funcionários são orientados a respeitar as normas de nossos clientes no que diz respeito à utilização e conservação dos equipamentos e das medidas de proteção coletiva oferecidas pelos nossos clientes, como por exemplo, corrimão, cabos guia, passarelas, regras de trânsito, guarda-corpo, além de orientação básicas de utilização de equipamentos de combate a princípio de incêndios.', 1, '2026-02-16 17:52:00.249413', '2026-02-28 21:57:36.030519');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (19, 'medidas_epi', 'MEDIDAS DE ORDEM INDIVIDUAL (EPI)', 'A {empresa} faz uso de suas normas e seus procedimentos para orientar, treinar e capacitar os funcionários quanto às medidas de ordem individuais (EPI) que proporcionam maior segurança na execução de suas tarefas.\n\nQuando comprovadas a inviabilidade técnica ou econômica para a implementação da proteção coletiva, a empresa fornecerá EPI conforme procedimentos específicos para as áreas envolvidas.\n\nO fornecimento do EPI, quando aplicável, para os colaboradores deve ser controlado por cada gerência vinculada às áreas operacionais. Os Coordenadores, Líderes e Supervisores deverão efetuar o registro e controle de entrega de EPI conforme Planilha de Controle de EPI.\n\nDepois de preenchida, esta planilha deve ficar armazenada nos arquivos das áreas operacionais para fins de registros e possível evidência requerida por órgãos trabalhistas e/ou clientes.\n\nCabe ao empregador quanto ao EPI:\na) adquirir o EPI adequado ao risco de cada atividade;\nb) exigir seu uso;\nc) fornecer ao trabalhador somente o aprovado pelo órgão nacional competente em matéria de segurança e saúde no trabalho;\nd) orientar e treinar o trabalhador sobre o uso adequado guarda e conservação;\ne) substituir imediatamente, quando danificado ou extraviado;\nf) responsabilizar-se pela higienização e manutenção periódica;\ng) comunicar ao MTE qualquer irregularidade observada;\nh) registrar o seu fornecimento ao trabalhador, podendo ser adotados livros, fichas ou sistema eletrônico.', 1, '2026-02-16 17:52:00.386467', '2026-02-28 21:57:36.312447');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (20, 'plano_acao', '10. PLANO DE AÇÃO', 'No Programa Gerenciamento de Riscos – PGR serão observadas e seguidas as seguintes etapas no plano de ação:\n\na) Antecipação e Reconhecimento dos riscos;\nb) Estabelecimento de prioridades e metas de avaliação e controle;\nc) Avaliação dos riscos e da exposição dos trabalhadores;\nd) Implantação de medidas de controle e avaliação de sua eficácia;\ne) Monitoramento da exposição aos riscos;\nf) Registro e divulgação de dados através de treinamentos informando sobre os riscos identificados;\ng) Prevenção, eliminação ou redução de agentes prejudiciais à saúde ou à integridade física dos trabalhadores.', 1, '2026-02-16 17:52:00.500244', '2026-02-28 21:57:35.700641');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (21, 'divulgacao', '13. DIVULGAÇÃO DO PROGRAMA', 'Os documentos e os procedimentos operacionais que integram o Programa de Gerenciamento de Risco (PGR) estarão disponíveis aos empregados.\n\nA atualização do PGR será realizada quando da ocorrência de alterações significativas de ordem tecnológica, operacional, legal ou regulatória que provoquem a necessidade de adequação dos documentos que o integram ou ainda quando for recomendado na auditoria anual.\n\nCabe aos responsáveis pelas respectivas áreas procederem a divulgação das atualizações dos documentos que integram o PGR, após as devidas aprovações, respeitadas eventuais restrições para o manuseio e circulação quando se tratarem de documentos controlados.\n\nEsses dados foram levantados por profissionais do departamento de QHSE (Qualidade, Saúde, Segurança e Meio Ambiente) com a participação dos responsáveis pelas áreas analisadas, designados de CIPA e dos próprios trabalhadores e inseridos no Inventário de Riscos deste PGR.', 1, '2026-02-16 17:52:00.614256', '2026-02-28 21:57:37.432750');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (22, 'recomendacoes', '14. RECOMENDAÇÕES GERAIS', '- Aplicação de medidas, sempre que necessárias, de caráter administrativo ou da organização do trabalho.\n- Aplicação de Treinamento de Segurança em geral, sobre Uso de EPI, Cuidados com produtos de químicos, Levantamento de peso e Trabalho em Altura, assim como outros treinamentos que se fizerem necessários;\n- Aplicação de Treinamento para membro designado de segurança da CIPA, no setor, em cumprimento com a portaria 3214 de 08/06/78 – NR 05;\n- Dotação de creme protetor para as mãos para os funcionários que tiverem contato direto com graxas, óleos e outros produtos químicos durante a jornada de trabalho;\n- Fornecimento de EPIs adequados de acordo com Ficha Técnica de Classificação de EPI por Função;\n- Orientações sobre o uso correto e higiênico dos vestiários e asseio pessoal;\n- Execução do Gerenciamento de Riscos através da observação de segurança e uso dos EPIs;\n- Guarda de documentação do controle das intervenções de segurança do trabalho;\n- Aplicação de rígido controle médico dos empregados.', 1, '2026-02-16 17:52:00.727299', '2026-02-28 21:57:37.523070');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (23, 'legislacao', '15. LEGISLAÇÃO COMPLEMENTAR', 'Além de atender a Portaria SEPRT n° 6730 de 09 de março de 2020, o PGR atende uma série de outras normas e legislações complementares:\n\n- PORTARIA 3214/78 – NORMAS REGULAMENTADORAS\n- NORMAS DE HIGIENE OCUPACIONAL – FUNDACENTRO\n- ABNT ISO NBR 45001 – SISTEMA DE GESTÃO DE SEGURANÇA E SAÚDE OCUPACIONAL\n- ABNT ISO NBR 31000 – GESTÃO DE RISCOS – DIRETRIZES\n- ABNT NBR 5413 – ILUMINAÇÃO DE INTERIORES\n- ABNT NBR 10152 – NÍVEL DE RUÍDO PARA CONFORTO ACÚSTICO', 1, '2026-02-16 17:52:00.840586', '2026-02-28 21:57:37.614763');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (24, 'estrutura_registro', 'FORMA DE REGISTRO, MANUTENÇÃO E DIVULGAÇÃO DE DADOS', 'Este Documento Base, será apresentado aos Designados CIPA, ficando a disposição para consultas dos trabalhadores e órgãos oficiais de fiscalização.', 1, '2026-02-28 21:57:31.715714', '2026-02-28 21:57:31.715732');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (25, 'estrutura_implantacao', 'IMPLANTAÇÃO DO CRONOGRAMA DE AÇÃO', 'O Plano de ação com seu cronograma será apresentado às Hierarquias superiores, à Designados CIPA e os registros das ações serão mantidos em arquivo sob responsabilidade do funcionário responsável pela Segurança do Trabalho, por período de 20 anos, fazendo divulgação das soluções propostas, através dos meios de comunicação existentes na empresa.', 1, '2026-02-28 21:57:31.951633', '2026-02-28 21:57:31.951680');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (26, 'estrutura_eficacia', 'ANÁLISE DA EFICÁCIA E CORREÇÕES DAS METAS E PRIORIDADES', 'A análise da eficácia e as correções das metas e prioridades serão realizadas, considerando as avaliações do ambiente de trabalho, os dados coletados com os trabalhadores e a verificação de possíveis alterações nos setores de trabalho. O cronograma de ações será alterado conforme as correções das metas e prioridades estabelecidas.\n\nEste Documento Base, será apresentado em reunião de Designados CIPA, ficando a disposição para consultas dos trabalhadores e órgãos oficiais de fiscalização.', 1, '2026-02-28 21:57:32.105365', '2026-02-28 21:57:32.105412');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (27, 'resp_informacao', 'DA INFORMAÇÃO', 'a) Consultar os trabalhadores quanto à percepção de riscos ocupacionais, podendo para este fim ser adotadas as manifestações da Comissão Interna de Prevenção de Acidentes - CIPA, quando houver; e\nb) Comunicar aos trabalhadores sobre os riscos consolidados no inventário de riscos e as medidas de prevenção do plano de ação do PGR.', 1, '2026-02-28 21:57:32.434850', '2026-02-28 21:57:32.434898');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (28, 'resp_procedimentos', 'PROCEDIMENTOS', 'a) Cabe a Alta Direção e superiores hierárquicos: Apoiar a implantação, manutenção e desenvolvimento do PGR e das atividades prevencionistas e efetivar normas, instruções e programas estabelecidos pelo Ministério do Trabalho e Emprego.\nb) Desenvolver, administrar e inspecionar as atividades de prevenção de acidentes, cumprindo os dispositivos legais vigentes.\nc) Orientar e assessorar os diversos órgãos da Empresa de forma a garantir o desempenho dos mesmos, na aplicação dos programas de segurança estabelecidos.\nd) Elaborar e propor normas, instruções e regulamentos de Segurança e Higiene do Trabalho.\ne) Manter, obrigatoriamente, programa de inspeção de segurança visando levantar os riscos de acidentes.\nf) Investigar os acidentes, elaborar e colocar em prática os procedimentos específicos, incluindo atribuições a todos que possam vir a participar nas investigações.\ng) Manter registros de acidentes e todos os detalhes necessários aos estudos estatísticos e funcionais, da prevenção de acidentes.\nh) Elaborar programas e ministrar treinamento geral e específico, de segurança e medicina do trabalho e promover campanhas internas de prevenção de acidentes e higiene do trabalho.', 1, '2026-02-28 21:57:32.554563', '2026-02-28 21:57:32.554606');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (29, 'resp_seguranca', 'DA SEGURANÇA DO TRABALHO', 'a) Elaborar, estabelecer, implantar, assegurar a manutenção do programa, acompanhar e monitorar, bem como promover o comprometimento, envolvimento, treinamentos sobre a importância do programa e oferecer suporte técnico, de acordo com a solicitação da empresa.', 1, '2026-02-28 21:57:32.678597', '2026-02-28 21:57:32.678642');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (30, 'resp_cipa', 'DO AGENTE DE PREVENÇÃO DE ACIDENTES / DESIGNADOS DE CIPA', 'a) Conhecer o PGR da Empresa e relacionar-se com a Engenharia de Segurança do Trabalho, no sentido de participar das ações de prevenção dos infortúnios e doenças do trabalho junto aos empregados, como também no controle das ações de segurança programadas na Empresa.\nb) O representante designado pela {empresa}, devidamente treinado, irá atuar na coordenação de todas as atividades relativas à Segurança e Saúde.', 1, '2026-02-28 21:57:32.799352', '2026-02-28 21:57:32.799397');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (31, 'resp_medicina', 'DA MEDICINA DO TRABALHO', 'a) Informar, ao responsável pelo PGR, as alterações biológicas ocorridas com os empregados;\nb) Contribuir com as informações técnicas sobre os riscos à saúde, que podem ser causados pelos agentes de risco;\nc) Desenvolver o PCMSO.', 1, '2026-02-28 21:57:32.920478', '2026-02-28 21:57:32.920524');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (32, 'resp_supervisao', 'DA SUPERVISÃO', 'a) Colaborar em todas as ações que se fizerem necessárias à implantação do programa e promover a motivação de todas as pessoas da unidade a que pertence;\nb) Informar aos trabalhadores de maneira apropriada e suficiente, sobre os riscos ambientais que possam existir nos locais de trabalho e sobre os meios disponíveis para prevenir ou limitar a ação dos mesmos.\nc) Cumprir e fazer cumprir as disposições legais e regulamentares sobre segurança e saúde no trabalho;\nd) Informar aos trabalhadores, quanto aos riscos existentes no local de trabalho e medidas prevenção adotadas para eliminação de riscos;\ne) Inspecionar, permanentemente, as operações, equipamentos, máquinas e edificações, em suas áreas de atuação, visando eliminar riscos de acidentes.\nf) Permitir que representantes dos trabalhadores acompanhem a fiscalização dos preceitos legais e regulamentares sobre segurança e saúde no trabalho;\ng) Determinar procedimentos que devem ser adotados em caso de acidente ou doença relacionada ao trabalho, incluindo a análise de suas causas;\nh) Disponibilizar à Inspeção do Trabalho todas as informações relativas à segurança e saúde no trabalho;\ni) Implementar medidas de prevenção, ouvidos os trabalhadores, de acordo com a seguinte ordem de prioridade;\nj) Eliminação dos fatores de risco;\nk) Informar à administração a ocorrência de acidentes do trabalho quando houver;\nl) Minimização e controle dos fatores de risco, com a adoção de medidas administrativas ou de organização do trabalho.', 1, '2026-02-28 21:57:33.043159', '2026-02-28 21:57:33.043206');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (33, 'diretrizes', '6. DIRETRIZES', '', 1, '2026-02-28 21:57:33.257826', '2026-02-28 21:57:33.257851');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (34, 'diretrizes_estrategia', 'ESTRATÉGIA', 'DIREÇÃO\nEste PGR está sendo elaborado pela área de Segurança do Trabalho da {empresa} e com apoio operacional para implantação.\n\nCOLABORADORES\nTodos os empregados em todos os cargos devem colaborar e participar de forma efetiva dentro de seu setor de trabalho, com informações, para que este Programa alcance seus objetivos.\n\nRECURSOS\nDeverão ser disponibilizados recursos humanos, materiais e financeiros, para a elaboração e execução do "Programa"; das medidas de controle, dos monitoramentos e das atualizações permanentes, conforme exigência Legal do Ministério do Trabalho e Emprego.', 1, '2026-02-28 21:57:33.378556', '2026-02-28 21:57:33.378601');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (35, 'metodo_biologico', 'AGENTES BIOLÓGICOS', 'Consideram-se agentes biológicos as bactérias, fungos, bacilos, parasitas, protozoários, vírus, microrganismos, entre outros, e a avaliação será qualitativa, com base no serviço prestado.', 1, '2026-02-28 21:57:33.954270', '2026-02-28 21:57:33.954317');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (36, 'metodo_ergonomico', 'AGENTES ERGONÔMICOS', 'Relatório de Avaliação de Condições Ergonômicas, conforme NR 17 da Portaria 3214/78, será realizado anualmente, ou quando houver mudanças significativas no ambiente de trabalho.', 1, '2026-02-28 21:57:34.100360', '2026-02-28 21:57:34.100406');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (37, 'metodo_mecanico', 'AGENTES MECÂNICOS E ACIDENTES', 'Por se tratar de risco de acidente sua metodologia e caracterização passa pela utilização da ferramenta Análise Preliminar de Risco – APR, e considera as situações que envolvam acidentes do tipo mecânico advindo de atividades "braçais", de organização e distribuição de layout, atividades especificas que envolvam risco de movimentação manual de peças ou equipamentos, bem como a movimentação do trabalhador dentro da empresa, trabalhos em altura e trabalhos com eletricidade.', 1, '2026-02-28 21:57:34.222030', '2026-02-28 21:57:34.222078');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (38, 'inventario_riscos_intro', '9. INVENTÁRIO DE RISCOS, PERIGOS, ASPECTOS E IMPACTOS', 'RISCOS AMBIENTAIS E OCUPACIONAIS\n\nDurante as avaliações serão considerados os seguintes aspectos:', 1, '2026-02-28 21:57:34.350789', '2026-02-28 21:57:34.350836');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (39, 'inventario_tab_probabilidade', 'TABELA 1 – CRITÉRIOS PARA GRADAÇÃO DA PROBABILIDADE DE OCORRÊNCIA DO DANO (P)', 'Conceito que caracteriza a chance de que o perigo se concretize, ou seja, a probabilidade de consequência prejudicial ao ser humano ou a empresa, caso permita-se que as condições inseguras persistam.\n\nPROBABILIDADE (P)\nNível | Classificação | Descrição | Frequência\n1 | IMPROVÁVEL | Probabilidade de 1 ocorrência até uma vez em cada 50 anos | (P ≤ 1 ocorrência/50 anos)\n2 | REMOTO | Probabilidade de 1 ocorrência em cada 5 anos | (1 ocorrência/50 anos < P ≤ 1 ocorrência/5 anos)\n3 | OCASIONAL | Probabilidade de 1 ocorrência em cada ano | (1 ocorrência/5 anos < P ≤ 1 ocorrência/ano)\n4 | PROVÁVEL | Probabilidade de 1 ocorrência em cada mês | (1 ocorrência/ano < P ≤ 1 ocorrência/mês)\n5 | FREQUENTE | Probabilidade de ocorrência mais do que uma vez por mês | (P > 1 ocorrência/mês)\n\nOBSERVAÇÃO\nSe a exposição a contaminantes atmosféricos ou ao ruído for avaliada como excessiva, ou seja, maior que o limite de exposição permitido, ou acima do nível de ação, deve-se definir o índice de probabilidade de ocorrência do dano estimado como 1, 2, 3, 4 ou 5 por julgamento profissional do avaliador, conforme o grau de adequação do EPI ao tipo de exposição, sua manutenção e uso efetivo.', 1, '2026-02-28 21:57:34.478542', '2026-02-28 21:57:34.478590');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (40, 'inventario_tab_gravidade', 'TABELA 2 – CRITÉRIOS PARA GRADAÇÃO DA GRAVIDADE DO DANO (G)', 'Para a gradação da gravidade do dano potencial (efeito crítico) atribui-se um índice de gravidade (G) variando de 1 a 5 conforme os critérios da tabela abaixo.\n\nGRAVIDADE (G)\nNível | Classificação | Descrição\n1 | NEGLIGENCIÁVEL | Danos pessoais ligeiros ou sem danos, mal-estar passageiro, pequenas lesões sem qualquer tipo de incapacidade. (Sem baixa)\n2 | MARGINAL | Danos ou doenças ocupacionais menores com ou sem incapacidade temporária sem assistência médica especializada, primeiro socorro. (Lesões ou doenças até 10 dias de baixa)\n3 | MODERADO | Danos ou doenças ocupacionais de média gravidade, requerendo assistência médica e baixa com duração superior a 10 dias. (Lesões ou doenças suscetíveis de provocar baixa de duração compreendida entre 11 e 60 dias)\n4 | GRAVE | Danos ou doenças ocupacionais graves, lesões com incapacidade temporária ou parcial permanente, internamento hospitalar. (Incapacidade parcial permanente, ou lesões ou doenças suscetíveis de provocar baixa de duração superior a 60 dias)\n5 | CRÍTICO | Morte ou incapacidade total permanente', 1, '2026-02-28 21:57:34.601653', '2026-02-28 21:57:34.601700');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (41, 'inventario_tab_exposicao', 'TABELA 3 – MONITORAMENTO DA EXPOSIÇÃO (GRAU DE EXPOSIÇÃO AO RISCO)', 'Para a gradação da exposição ao dano potencial (efeito crítico) atribui-se um índice de exposição (E) variando de 1 a 5 conforme os critérios da Tabela 3.\n\nEXPOSIÇÃO (E)\nNível | Classificação | Descrição\n1 | ESPORÁDICA | Exposição acontece pelo menos uma vez por ano por um período curto de tempo ou nunca acontece\n2 | POUCO FREQUENTE | Exposição acontece algumas vezes por mês\n3 | OCASIONAL | Exposição acontece várias vezes por semana ou várias vezes por dia por períodos curtos (< 60 min.)\n4 | FREQUENTE | Exposição ocorre várias vezes por dia por períodos não prolongados (< 120 min. seguidos)\n5 | CONTÍNUA | Exposição por períodos diários ou várias vezes por dia por períodos prolongados (> 120 min. seguidos)', 1, '2026-02-28 21:57:34.779365', '2026-02-28 21:57:34.779411');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (42, 'inventario_tab_matriz_severidade', 'TABELA 4 – MATRIZ DE RISCO PARA ESTIMAR A SEVERIDADE DO RISCO', 'Estimar e definir a categoria de cada risco, a partir da combinação dos valores atribuídos para exposição (E) e gravidade (G) do dano, utilizando a matriz apresentada na Tabela 4.\n\nMATRIZ GRAVIDADE (G) x EXPOSIÇÃO (E) → SEVERIDADE\n\n         |  G=1  |  G=2  |  G=3  |  G=4  |  G=5\nE=1      |   A   |   A   |   A   |   B   |   B\nE=2      |   A   |   B   |   B   |   C   |   D\nE=3      |   A   |   B   |   C   |   D   |   D\nE=4      |   B   |   C   |   D   |   E   |   E\nE=5      |   B   |   D   |   D   |   E   |   E', 1, '2026-02-28 21:57:34.930761', '2026-02-28 21:57:34.930807');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (43, 'inventario_tab_severidade', 'TABELA 5 – CRITÉRIOS PARA GRADAÇÃO DA SEVERIDADE DO DANO (S)', 'SEVERIDADE (S)\nNível | Classificação\nA | NEGLIGENCIÁVEL\nB | MARGINAL\nC | GRAVE\nD | MUITO GRAVE\nE | CRÍTICO', 1, '2026-02-28 21:57:35.056474', '2026-02-28 21:57:35.056520');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (44, 'inventario_tab_acoes_mitigacao', 'TABELA 6 – AÇÕES A SEREM ADOTADAS DE FORMA A MITIGAR O RISCO', 'Serão priorizadas as medidas de controle coletivo dos agentes nocivos à Segurança e Saúde dos Trabalhadores de acordo com a seguinte ordem abaixo.\n\nPriorização | Medida | Significado | Descrição | Redução do Risco\n1° | E - Eliminação | Eliminação total da fonte de risco | 100%\n2° | S - Substituição ou Minimização | Substituição de matérias-primas, equipamentos e procedimento de trabalho | 40%\n3° | CE - Controle de Engenharia | Enclausuramento, adaptação do ambiente de trabalho, automatização do processo e etc. | 25%\n4° | CA - Controle Administrativo | Sinalização, treinamentos, exames médicos, implementação de procedimento de segurança e etc. | 15%\n5° | DP - Dispositivo de Proteção | Uso de EPIs e implementação de EPCs | 10%\n\nQuando, em qualquer fase do Programa, os riscos detectados ultrapassarem os valores limites das normas utilizadas, serão adotadas medidas de controle, com o objetivo de eliminar ou reduzir a exposição ao risco.\n\nSituações de risco grave e iminente serão comunicados ao supervisor da área, que deverá tomar medidas para eliminação do agente causador, sob risco de interdição do local.', 1, '2026-02-28 21:57:35.203063', '2026-02-28 21:57:35.203111');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (45, 'inventario_tab_priorizacao', 'TABELA 7 – CRITÉRIOS PARA PRIORIZAÇÃO DAS AÇÕES', 'Para priorização das ações será avaliado a Severidade (S) após a verificação das medidas de controle adotadas, juntamente com o grau de Probabilidade (P).\n\nRISCO (R)\nClassificação do Risco | Prazo para Ações\nBaixo | Aceitável\nTolerável | < 01 (um) ano\nModerado | < 06 (seis) meses\nSignificativo | Paralização\n\nSe o risco for considerado aceitável, não será necessário adotar ações de mitigação do risco.', 1, '2026-02-28 21:57:35.326830', '2026-02-28 21:57:35.326877');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (46, 'inventario_tab_matriz_risco', 'TABELA 8 – TABELA PARA ESTIMAR A CLASSIFICAÇÃO DO RISCO', 'MATRIZ SEVERIDADE (S) x PROBABILIDADE (P) → CLASSIFICAÇÃO DO RISCO\n\n         |  S=A  |  S=B  |  S=C  |  S=D  |  S=E\nP=1      |   B   |   B   |   B   |   T   |   T\nP=2      |   B   |   B   |   T   |   M   |   M\nP=3      |   B   |   T   |   M   |   M   |   S\nP=4      |   T   |   M   |   M   |   S   |   S\nP=5      |   T   |   M   |   S   |   S   |   S\n\nLegenda: B = Baixo | T = Tolerável | M = Moderado | S = Significativo\n\nCaso a tabela 7 indique que para determinado risco não é necessário realizar uma ação específica, mas a empresa venha a receber uma autuação de organismo fiscalizador, ou venha acontecer algum acidente em decorrência do perigo relacionado ao risco, deve-se realizar alguma ação para minimizar esse risco, independente do resultado obtido na tabela.\n\nO plano de ação deve ser amplo e deve atender as reais necessidades de melhoria da empresa, não se prendendo somente as exigências da NR 01.', 1, '2026-02-28 21:57:35.448072', '2026-02-28 21:57:35.448118');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (47, 'inventario_excecoes', 'EXCEÇÕES NA DEFINIÇÃO DA PERIODICIDADE DE MONITORAMENTOS', 'Ruído – se as exposições forem superiores ao limite de tolerância ou nível de ação, mas as condições se mantiverem constantes e o controle for baseado apenas no uso de equipamento de proteção individual avaliado como eficaz, a periodicidade do monitoramento poderá ser reduzida a critério do avaliador.\n\nTambém a critério do avaliador a periodicidade do monitoramento para outras exposições poderá ser reduzida se as condições de trabalho forem estáveis e a incerteza das avaliações for baixa, exceto se houver exigência legal em contrário.', 1, '2026-02-28 21:57:35.569008', '2026-02-28 21:57:35.569054');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (48, 'plano_acao_documentacao', 'DOCUMENTAÇÃO', 'O PGR deve conter, no mínimo, os seguintes documentos:\na) inventário de riscos;\nb) plano de ação.\n\nComo metodologia de execução do plano de ação, estabeleceu o método 5 porquês como ferramenta para construção objetiva das soluções que serão implantadas neste PGR, desta forma o gerenciamento dos riscos ocupacionais poderá estar detalhado neste documento e seu resumo controlado pela planilha GRO.\n\nAs metodologias de investigação vão auxiliar no mapeamento e na padronização de processos de análise de riscos, cumprindo suas etapas a indefinição dará lugar à produtividade na resolução dos problemas (perigos) detectados no inventário de perigos, riscos, aspectos e impactos tendo em vista que todos os envolvidos têm o conhecimento exato de o que fazer, quando, onde, de que forma, porquê, etc.\n\nComo resultado, além do ganho de produtividade, constrói-se sinergia que, hoje em dia é extremamente importante para construção de um diferencial estratégico para qualquer negócio.', 1, '2026-02-28 21:57:35.807091', '2026-02-28 21:57:35.807139');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (49, 'medidas_administrativas', 'MEDIDAS ADMINISTRATIVAS OU DE ORGANIZAÇÃO DO TRABALHO', 'A {empresa} possui procedimentos de segurança e saúde ocupacional, que são repassados para os funcionários através de treinamentos e material de informações contendo todas as normas da empresa no que diz respeito à segurança e saúde ocupacional.\n\nOs funcionários recebem uma ordem de serviço (OSS) contendo suas obrigações no que diz respeito à segurança e saúde, assim como as penalidades pelo descumprimento das normas de segurança impostas pela legislação vigente, pela {empresa} e pelo Cliente.', 1, '2026-02-28 21:57:36.161981', '2026-02-28 21:57:36.162030');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (50, 'medidas_uso_epi', 'USO, GUARDA, HIGIENIZAÇÃO E CONSERVAÇÃO DO EPI', 'O EPI deve ser utilizado apenas para a finalidade a que se destina e guardado com o próprio usuário. Sua conservação deve ser realizada conforme treinamento aplicado pela {empresa} ou instruções de uso definidas pelo fabricante.\n\nA {empresa} não realiza e nem solicita aos fabricantes readequação de EPI. O EPI quando apresenta algum tipo de problema é imediatamente substituído. Em caso de C.A vencido a {empresa} entra em contato com o fornecedor para verificar a possibilidade de troca do mesmo, ou o fornecimento de documento de solicitação de renovação do C.A junto ao MTE, quando vencido o prazo de validade estipulado pelo órgão nacional competente em matéria de segurança e saúde do trabalho. Quando nenhuma dessas opções for obtida o EPI deverá ser substituído.\n\nA {empresa} não realiza higienização do EPI, eles são simplesmente substituídos.\n\nCabe ao colaborador quanto ao EPI:\na) Usar o EPI apenas para a finalidade a que se destina;\nb) responsabilizar-se pela guarda e conservação;\nc) comunicar ao empregador qualquer alteração que o torne impróprio para uso;\nd) cumprir as determinações do empregador sobre o uso adequado.', 1, '2026-02-28 21:57:36.421977', '2026-02-28 21:57:36.422027');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (51, 'medidas_substituicao_epi', 'SUBSTITUIÇÃO E REPOSIÇÃO DO EPI', 'É responsabilidade do empregado, comunicar a sua gerência imediata, sobre qualquer alteração no EPI que o torne impróprio para uso, além da perda ou extravio do equipamento solicitando sua reposição. No caso de EPI impróprio para uso, o mesmo deverá ser devolvido na ocasião de sua reposição, para posterior descarte.', 1, '2026-02-28 21:57:36.583357', '2026-02-28 21:57:36.583405');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (52, 'medidas_protecao_geral', 'MEDIDAS DE PROTEÇÃO – EPC, EPI E OUTRAS', 'a) Medidas que eliminam ou reduzam a utilização ou a formação de agentes prejudiciais à saúde;\nb) Medidas que previnem a liberação ou disseminação desses agentes no ambiente de trabalho;\nc) Medidas que reduzem os níveis ou a concentração desses agentes nos ambientes de trabalho;\nd) Medidas de caráter administrativo ou de organização do trabalho;\ne) Medidas de ordem individual (Equipamento de Proteção Individual – EPI):\nf) Seleção do EPI adequado tecnicamente ao risco a que o trabalhador está exposto e a atividade exercida;\ng) Programa de treinamento dos trabalhadores quanto a sua correta utilização e orientação sobre as limitações de proteção que o EPI oferece;\nh) Critérios e mecanismos de avaliação da eficácia das medidas de proteção, conforme análise e dados do PCMSO.', 1, '2026-02-28 21:57:36.751718', '2026-02-28 21:57:36.751764');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (53, 'medidas_monitoramento', 'MONITORAMENTO DO RISCO', 'Todas as medidas de controle, existentes ou implantadas, serão avaliadas periodicamente, tendo como base as avaliações ambientais e o PCMSO.\n\nO PGR também será avaliado periodicamente, em concordância com o cronograma implantado e por período nunca superior a 2 (dois) anos.', 1, '2026-02-28 21:57:36.901928', '2026-02-28 21:57:36.901970');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (54, 'medidas_registro_divulgacao', 'REGISTRO E DIVULGAÇÃO DE DADOS', 'O registro e a divulgação de dados são estruturados de forma a constituir um histórico técnico e administrativo do desenvolvimento do Programa.\n\nOs dados serão mantidos por um período mínimo de 20 (vinte) anos. O registro de dados estará sempre disponível aos trabalhadores interessados ou de seus representantes legais e para as autoridades competentes.', 1, '2026-02-28 21:57:37.022937', '2026-02-28 21:57:37.022984');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (55, 'medidas_recomendacao_epi', 'RECOMENDAÇÃO ESPECIAL (EPI)', 'Deverá ser utilizada a "Ficha de Controle de EPIs – Equipamentos de Proteção Individual", conforme determinação de ordem legal, para registro de 1ª (primeira) dotação e substituição dos EPIs (Equipamentos de Proteção Individual) quando necessário, em função dos riscos existentes no ambiente de trabalho.\n\nCONSOLIDAÇÃO DAS LEIS DO TRABALHO – CLT\nArt. 158 – Cabe aos empregados:\nI – Observar as normas de segurança e medicina do trabalho, inclusive as instruções de que trata o item II do artigo anterior;\nII – Colaborar com a empresa na aplicação dos dispositivos deste capítulo.\n\nParágrafo Único: Constitui ato faltoso do empregado a recusa injustificada:\na) ...\nb) ao uso dos equipamentos de proteção individual fornecidos pela empresa.', 1, '2026-02-28 21:57:37.176516', '2026-02-28 21:57:37.176561');
INSERT INTO `pgr_secao_texto_padrao` (`id`, `secao`, `titulo`, `conteudo_padrao`, `ativo`, `criado_em`, `atualizado_em`) VALUES (56, 'cronograma_acoes', '12. CRONOGRAMA DE AÇÕES', 'O cronograma de ações abaixo apresenta as atividades necessárias para o cumprimento do PGR, com seus respectivos públicos alvo, periodicidade de realização e próxima avaliação/revisão prevista.\n\nCM = contrato de manutenção\n\n*** O cronograma detalhado é gerado automaticamente a partir dos dados cadastrados no sistema (model CronogramaAcaoPGR). ***', 1, '2026-02-28 21:57:37.301146', '2026-02-28 21:57:37.301194');
