INSERT INTO `seguranca_trabalho_equipamento` (`id`, `nome`, `modelo`, `certificado_aprovacao`, `data_cadastro`, `data_validade_ca`, `vida_util_dias`, `estoque_minimo`, `requer_numero_serie`, `foto`, `observacoes`, `ativo`, `fabricante_id`, `filial_id`, `estoque_atual`) VALUES (1, 'Luva Alta Tensão Classe 1 – 7,5 Kv 10', '66110', '29774', '2026-01-26', '2029-10-01', 1825, 3, 1, 'epi_fotos/LUVA-ISOLANTE-ORION-ALTA-TENSAO_Sa4IF6c.png', 'DESCRIÇÃO TÉCNICA ESPECÍFICA:\r\n\r\nCaracterísticas da Luva de Alta Tensão 10kV Classe 1 Tipo II Orion:\r\n\r\n– Luva de segurança isolante de borracha, projetada para proteção contra riscos de choque elétrico.\r\n\r\n– É confeccionada em borracha na cor preta, seguindo as normas específicas ASTM D120/NBR 10622. A cor preta indica que a luva é adequada para a classe 1 de alta tensão.\r\n\r\n– Este EPI possui certificação compulsória, garantindo sua conformidade com os padrões de segurança.', 1, 1, 2, 42);
INSERT INTO `seguranca_trabalho_equipamento` (`id`, `nome`, `modelo`, `certificado_aprovacao`, `data_cadastro`, `data_validade_ca`, `vida_util_dias`, `estoque_minimo`, `requer_numero_serie`, `foto`, `observacoes`, `ativo`, `fabricante_id`, `filial_id`, `estoque_atual`) VALUES (2, 'Óculos de Segurança', 'Danny Steel Pro Lente', '20716', '2026-02-25', '2028-02-25', 1460, 5, 0, 'epi_fotos/OCULOS-DE-SEGURANCA-DANNY-STEEL.webp', 'Teste$$$$$$$$$$$$$$$$$$', 1, 2, 1, 3);
INSERT INTO `seguranca_trabalho_equipamento` (`id`, `nome`, `modelo`, `certificado_aprovacao`, `data_cadastro`, `data_validade_ca`, `vida_util_dias`, `estoque_minimo`, `requer_numero_serie`, `foto`, `observacoes`, `ativo`, `fabricante_id`, `filial_id`, `estoque_atual`) VALUES (3, 'Respirador de Seguranca Air Safety Semifacial Airtox II', 'Air Safety Semifacial Airtox II', '5757', '2026-03-04', '2029-03-05', 1460, 3, 0, 'epi_fotos/RESPIRADOR-DE-SEGURANCA-AIR-SAFETY-SEMIFACIAL-AIRTOX-II.webp', 'O Respirador de Segurança Air Safety trata-se de peça semifacial que, com seu respectivo filtro de rosca contra partículas, químico ou combinado, forma o conjunto respirador e purificador. É utilizado para proteção das vias respiratórias do usuário contra a inalação de partículas sólidas, quando utilizado com filtros mecânicos ou combinados, e contra gases e vapores quando utilizado com filtros químicos ou combinados. Benefícios: Com suas normas e certificações, o Respirador de Segurança Air Safety consegue realizar a sua proteção respiratória a fim de reduzir a exposição da pele e das membranas mucosas a agentes de risco de quaisquer naturezas, é, portanto, um equipamento de proteção individual que gera conforto, segurança e estabilidade ao usuário. Características: O Respirador de Segurança Air Safety possui corpo confeccionado em elastômero nas cores preta, azul ou amarelo e cada peça possui três aberturas em seu corpo, duas em cada lateral e uma na parte central inferior. Nas aberturas laterais existem dois dispositivos, um de cada lado, plásticos, dotados de tampa, com válvula de exalação na parte interna. Na abertura central inferior, observa-se um bocal de material plástico dotado de uma válvula de inalação na parte traseira. O bocal é confeccionado de material plástico rígido e é dotado de uma rosca interna na sua parte frontal, com um anel de vedação para fixação dos filtros. Contém em seu design também um sistema de hastes laterais, em que são fixadas as presilhas de um tirante de cabeça, sendo este dotado de um suporte para a nuca. CA: 5757 Normas Técnicas: NBR 13697/2010 / ABNT NBR 13694:1996 / NBR 13696/2010', 1, 2, 1, 8);
INSERT INTO `seguranca_trabalho_equipamento` (`id`, `nome`, `modelo`, `certificado_aprovacao`, `data_cadastro`, `data_validade_ca`, `vida_util_dias`, `estoque_minimo`, `requer_numero_serie`, `foto`, `observacoes`, `ativo`, `fabricante_id`, `filial_id`, `estoque_atual`) VALUES (4, 'Creme Protetor para as Maos PM1000', 'PM1000', '9050', '2026-03-06', '2029-12-31', 365, 5, 0, 'epi_fotos/S_PM1000_120g.jpg', 'Creme protetor para as maos - entrada via suprimentos', 1, 1, 1, 12);
