INSERT INTO `seguranca_trabalho_funcao` (`id`, `nome`, `descricao`, `ativo`, `filial_id`, `registro`) VALUES (1, 'ASSISTENTE DE PLANEJAMENTO', 'O Assistente de PCM é responsável por suportar o Engenheiro ou Técnico de PCM na organização, programação e acompanhamento das atividades de manutenção.', 1, 1, 2000);
INSERT INTO `seguranca_trabalho_funcao` (`id`, `nome`, `descricao`, `ativo`, `filial_id`, `registro`) VALUES (2, 'Coordenador de Planejamento', 'O Técnico de Planejamento e Programação da Manutenção planeja, programa e controla os serviços de manutenção preventiva, preditiva e corretiva de máquinas, equipamentos e instalações relacionadas à produção industrial. Propõe melhorias para aumentar a produtividade da produção, por meio da manutenção produtiva. Trata e disponibiliza as informações do setor de manutenção industrial. Cumpre normas técnicas e de qualidade, procedimentos da empresa e normas regulamentadoras de saúde e segurança no trabalho e de preservação ambiental.', 1, 2, 0);
