INSERT INTO `tarefas_tarefas` (`id`, `recorrente`, `frequencia_recorrencia`, `data_fim_recorrencia`, `titulo`, `descricao`, `data_criacao`, `data_atualizacao`, `data_inicio`, `prazo`, `concluida_em`, `status`, `prioridade`, `projeto`, `duracao_prevista`, `tempo_gasto`, `dias_lembrete`, `ata_reuniao`, `filial_id`, `responsavel_id`, `tarefa_recorrencia_pai_id`, `usuario_id`, `aviso_fim_enviado_em`, `dias_aviso_fim_recorrencia`, `lembrete_enviado_em`, `recorrencia_encerrada`) VALUES (42, 0, '', NULL, 'Criação usuários Minas', 'Estou querendo evoluir o teste da plataforma aqui em Minas com 2 pessoas que trabalham comigo.\r\nmatheus.monteiro@cetest.com.br\r\nvinicius.calassa@cetestminas.com.br\r\n\r\nConsegue criar no ambiente MG?', '2026-04-24 18:59:55.699492', '2026-04-30 01:41:00.611312', '2026-04-24 15:00:00', '2026-04-28 15:00:00', '2026-05-01 19:59:00.758319', 'concluida', 'baixa', 'CADASTRO DE USUÁRIO', NULL, NULL, 0, '1', 1, 1, NULL, 6, NULL, 30, NULL, 0);
INSERT INTO `tarefas_tarefas` (`id`, `recorrente`, `frequencia_recorrencia`, `data_fim_recorrencia`, `titulo`, `descricao`, `data_criacao`, `data_atualizacao`, `data_inicio`, `prazo`, `concluida_em`, `status`, `prioridade`, `projeto`, `duracao_prevista`, `tempo_gasto`, `dias_lembrete`, `ata_reuniao`, `filial_id`, `responsavel_id`, `tarefa_recorrencia_pai_id`, `usuario_id`, `aviso_fim_enviado_em`, `dias_aviso_fim_recorrencia`, `lembrete_enviado_em`, `recorrencia_encerrada`) VALUES (43, 0, '', NULL, 'Alinhamento FIS / GVG / Italo - SESC Interlagos', 'Fabio, segue abaixo minhas considerações:\r\n\r\n•	Empresa contratada pelo cliente é Brascon:\r\n\r\nhttps://www.instagram.com/brascon_refrig/\r\nhttps://cnpj.biz/06236903000152\r\n\r\n•	Acho valido a contratação da Midea,  o responsável pela emissão desses orçamentos é o André Oliveira o mesmo que tratamos sobre o TRT SP, com base em um orçamento que ele emitiu para um outro cliente nosso o Serasa estão cobrando em média de R$4.900,00 a visita, no momento o equipamento se encontra sem placas eletrônicas que estão com a empresa Brascon, ainda não tem previsão de retorno;\r\n•	As peças de nossa responsabilidade foram compradas e entregues no contrato;\r\n•	Conseguimos a reversão de 2 SLA’s glosados nos meses de setembro e Outbro/2025;\r\n•	Sobre os orçamentos de peças eu cuidarei pessoalmente e vou te passando;\r\n•	Sobre o orçamento das maquinas novas já passei ao Giovanni;', '2026-04-27 12:43:12.079364', '2026-05-06 19:14:24.277564', '2026-04-27 15:00:00', '2026-05-15 15:00:00', NULL, 'atrasada', 'baixa', 'CM-830 SESC', NULL, NULL, 0, '', 1, 3, NULL, 6, NULL, 30, NULL, 0);
