INSERT INTO `tarefas_tarefas` (`id`, `recorrente`, `frequencia_recorrencia`, `data_fim_recorrencia`, `titulo`, `descricao`, `data_criacao`, `data_atualizacao`, `data_inicio`, `prazo`, `concluida_em`, `status`, `prioridade`, `projeto`, `duracao_prevista`, `tempo_gasto`, `dias_lembrete`, `ata_reuniao`, `filial_id`, `responsavel_id`, `tarefa_recorrencia_pai_id`, `usuario_id`, `aviso_fim_enviado_em`, `dias_aviso_fim_recorrencia`, `lembrete_enviado_em`, `recorrencia_encerrada`) VALUES (50, 0, '', NULL, 'Setor da comedoria – balcão T02:', 'Setor da comedoria – balcão T02: o cliente solicitou atenção especial devido à recorrência de falhas. O Edison já está atuando no equipamento, com previsão de conclusão até 04/05, considerando que as intervenções só podem ocorrer às segundas-feiras;', '2026-04-27 18:13:59.007541', '2026-04-27 18:13:59.007580', '2026-05-04 15:00:00', NULL, NULL, 'andamento', 'baixa', 'CM-830 SESC GLOBAL', NULL, NULL, 0, '1', 1, 3, NULL, 3, NULL, 30, NULL, 0);
INSERT INTO `tarefas_tarefas` (`id`, `recorrente`, `frequencia_recorrencia`, `data_fim_recorrencia`, `titulo`, `descricao`, `data_criacao`, `data_atualizacao`, `data_inicio`, `prazo`, `concluida_em`, `status`, `prioridade`, `projeto`, `duracao_prevista`, `tempo_gasto`, `dias_lembrete`, `ata_reuniao`, `filial_id`, `responsavel_id`, `tarefa_recorrencia_pai_id`, `usuario_id`, `aviso_fim_enviado_em`, `dias_aviso_fim_recorrencia`, `lembrete_enviado_em`, `recorrencia_encerrada`) VALUES (51, 0, '', NULL, 'COMPRA DE FERIAS DO CARLOS BB BAURU', 'Boa tarde, Italo e Guilherme.\r\nSolicito autorização para a compra de 10 dias de férias do colaborador Carlos, do CM 820 BB Bauru.\r\nTemos a necessidade de realizar a cobertura do posto no mês de maio, referente ao saldo residual das férias do colaborador, originalmente previstas em janeiro. Diante disso, conversei com ele e houve concordância em realizar a venda desses 10 dias.\r\nDestaco que o custo estimado com transporte, estadia e alimentação para cobertura do período seria de R$ 3.064,00. Acredito que a alternativa mais viável financeiramente seria a compra das férias.\r\nFico no aguardo da autorização.', '2026-04-27 18:22:20.864459', '2026-04-27 18:22:20.864501', '2026-04-28 15:00:00', NULL, NULL, 'pendente', 'baixa', 'CM-820 BB BAURU', NULL, NULL, 0, '1', 1, 6, NULL, 3, NULL, 30, NULL, 0);
