INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (2, 'O que é a CIPA?', 'Conceito, objetivo e importância da CIPA nas organizações.', 1, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 15, 1, 1, '2026-03-07 22:22:24.621893', 2);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (3, 'Histórico da NR-5', 'Evolução da norma desde sua criação até as atualizações mais recentes.', 2, 'texto', '<h3>Histórico da NR-5</h3>\n<p>A NR-5 foi aprovada pela Portaria nº 3.214, de 08 de junho de 1978, pelo Ministério do Trabalho.</p>\n<h4>Principais marcos:</h4>\n<ul>\n    <li><strong>1978</strong> — Publicação original da NR-5</li>\n    <li><strong>1999</strong> — Reforma ampla com Portaria 08/1999</li>\n    <li><strong>2011</strong> — Atualização da Portaria 14/2011</li>\n    <li><strong>2022</strong> — Nova redação incluindo prevenção ao assédio</li>\n</ul>\n<p>A norma atual prevê a criação da CIPA em todos os estabelecimentos que se enquadrem\nno dimensionamento do Quadro I da NR-5.</p>', '', '', '', 10, 1, 1, '2026-03-07 22:22:24.639777', 2);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (4, 'Dimensionamento da CIPA', 'Como calcular o número de membros conforme o CNAE e quantidade de empregados.', 3, 'texto', '<h3>Dimensionamento da CIPA</h3>\n<p>O dimensionamento é feito pelo <strong>Quadro I da NR-5</strong>, cruzando:</p>\n<ol>\n    <li>O grupo econômico (CNAE) do estabelecimento</li>\n    <li>O número de empregados</li>\n</ol>\n<table class=\'table table-bordered\'>\n    <thead><tr><th>Nº Empregados</th><th>Efetivos</th><th>Suplentes</th></tr></thead>\n    <tbody>\n        <tr><td>20 a 29</td><td>1</td><td>1</td></tr>\n        <tr><td>30 a 50</td><td>2</td><td>2</td></tr>\n        <tr><td>51 a 80</td><td>3</td><td>3</td></tr>\n        <tr><td>81 a 120</td><td>4</td><td>3</td></tr>\n        <tr><td>121 a 140</td><td>5</td><td>4</td></tr>\n    </tbody>\n</table>', '', '', '', 12, 1, 1, '2026-03-07 22:22:24.658472', 2);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (5, 'Atribuições dos Membros da CIPA', 'Responsabilidades do presidente, vice-presidente, secretário e demais membros.', 1, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 20, 1, 1, '2026-03-07 22:22:24.694029', 3);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (6, 'Reuniões Ordinárias e Extraordinárias', 'Como conduzir reuniões, atas e deliberações da CIPA.', 2, 'texto', '<h3>Reuniões da CIPA</h3>\n<h4>Reuniões Ordinárias</h4>\n<p>Devem ser realizadas <strong>mensalmente</strong>, durante o expediente, em local apropriado. É obrigatória a lavratura de ata.</p>\n<h4>Reuniões Extraordinárias</h4>\n<p>Convocadas quando houver:</p>\n<ul>\n    <li>Denúncia de situação de risco grave e iminente</li>\n    <li>Ocorrência de acidente de trabalho grave ou fatal</li>\n    <li>Solicitação expressa de uma das representações</li>\n</ul>', '', '', '', 15, 1, 1, '2026-03-07 22:22:24.711007', 3);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (7, 'Mapa de Riscos', 'Elaboração do mapa de riscos ambientais do estabelecimento.', 3, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 25, 1, 1, '2026-03-07 22:22:24.729027', 3);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (8, 'Processo Eleitoral da CIPA', 'Passo a passo da eleição: edital, inscrição, votação e posse.', 1, 'texto', '<h3>Processo Eleitoral</h3>\n<h4>Etapas obrigatórias:</h4>\n<ol>\n    <li><strong>60 dias antes do término do mandato:</strong> Convocar eleição</li>\n    <li><strong>45 dias antes:</strong> Publicar e divulgar edital</li>\n    <li><strong>15 dias antes:</strong> Encerrar inscrições</li>\n    <li><strong>Dia da eleição:</strong> Votação secreta durante o expediente</li>\n    <li><strong>Após apuração:</strong> Posse dos eleitos no primeiro dia do mandato</li>\n</ol>\n<div class=\'alert alert-warning\'>\n    <strong>⚠️ Importante:</strong> O voto é secreto e a eleição deve ser realizada em dia normal de trabalho.\n</div>', '', '', '', 18, 1, 1, '2026-03-07 22:22:24.766271', 4);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (9, 'SIPAT — Semana Interna de Prevenção', 'Planejamento e execução da Semana Interna de Prevenção de Acidentes.', 2, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 20, 1, 1, '2026-03-07 22:22:24.785003', 4);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (10, 'O que é EPI?', 'Definição, finalidade e quando o EPI deve ser utilizado.', 1, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 12, 1, 1, '2026-03-07 22:22:25.829846', 5);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (11, 'Certificado de Aprovação (CA)', 'O que é o CA, sua importância e como verificar a validade.', 2, 'texto', '<h3>Certificado de Aprovação (CA)</h3>\n<p>Todo EPI comercializado no Brasil precisa ter o <strong>Certificado de Aprovação (CA)</strong>,\nemitido pelo Ministério do Trabalho.</p>\n<h4>Informações do CA:</h4>\n<ul>\n    <li>Número do CA</li>\n    <li>Nome do fabricante/importador</li>\n    <li>Data de validade (máximo 5 anos)</li>\n    <li>Norma técnica de referência</li>\n</ul>\n<div class=\'alert alert-danger\'>\n    <strong>⛔ Atenção:</strong> É proibido o uso de EPI sem CA válido!\n</div>', '', '', '', 10, 1, 1, '2026-03-07 22:22:25.847831', 5);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (12, 'EPIs para Proteção da Cabeça', 'Capacetes, bonés e capuzes de proteção.', 1, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 15, 1, 1, '2026-03-07 22:22:25.884093', 6);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (13, 'EPIs para Proteção Respiratória', 'Respiradores, máscaras e filtros — seleção por tipo de contaminante.', 2, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 18, 1, 1, '2026-03-07 22:22:25.902850', 6);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (14, 'EPIs para Proteção das Mãos e Membros Superiores', 'Luvas de diferentes materiais e suas aplicações.', 3, 'texto', '<h3>Proteção das Mãos</h3>\n<table class=\'table table-striped\'>\n    <thead><tr><th>Tipo de Luva</th><th>Proteção Contra</th></tr></thead>\n    <tbody>\n        <tr><td>Luva de Látex</td><td>Agentes biológicos, produtos químicos leves</td></tr>\n        <tr><td>Luva de Nitrila</td><td>Solventes, óleos, produtos químicos</td></tr>\n        <tr><td>Luva de Vaqueta</td><td>Abrasão, cortes leves, calor moderado</td></tr>\n        <tr><td>Luva de Malha de Aço</td><td>Cortes severos (açougues, indústria)</td></tr>\n        <tr><td>Luva Isolante</td><td>Choque elétrico (classe conforme tensão)</td></tr>\n    </tbody>\n</table>', '', '', '', 12, 1, 1, '2026-03-07 22:22:25.920415', 6);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (15, 'O que é Ergonomia?', 'Definição e campos de atuação da ergonomia.', 1, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 15, 1, 1, '2026-03-07 22:22:26.504717', 7);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (16, 'Análise Ergonômica do Trabalho (AET)', 'Metodologia para avaliação ergonômica do posto de trabalho.', 2, 'texto', '<h3>Análise Ergonômica do Trabalho</h3>\n<p>A AET é obrigatória conforme a NR-17 e deve contemplar:</p>\n<ol>\n    <li>Análise da demanda</li>\n    <li>Análise da tarefa</li>\n    <li>Análise da atividade</li>\n    <li>Diagnóstico</li>\n    <li>Recomendações</li>\n</ol>', '', '', '', 20, 1, 1, '2026-03-07 22:22:26.522658', 7);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (17, 'Postura Correta no Computador', 'Ajuste de cadeira, monitor, teclado e mouse.', 1, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 18, 1, 1, '2026-03-07 22:22:26.590795', 8);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (18, 'Ginástica Laboral', 'Exercícios preventivos para o ambiente de trabalho.', 2, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 12, 1, 1, '2026-03-07 22:22:26.609463', 8);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (20, 'Classificação ABNT NBR 10004', 'Classes I (perigosos) e II (não perigosos) de resíduos sólidos.', 1, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 15, 1, 1, '2026-03-07 22:25:49.731497', 10);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (21, 'Introdução à NR-35', 'Campo de aplicação, definições e responsabilidades.', 1, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 20, 1, 1, '2026-03-07 22:28:37.267412', 11);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (22, 'Análise de Risco e Permissão de Trabalho', 'Como elaborar a AR e a PT para trabalho em altura.', 2, 'texto', '<h3>Análise de Risco (AR)</h3>\n<p>Deve ser realizada <strong>antes de qualquer atividade</strong> em altura e incluir:</p>\n<ul>\n    <li>Identificação dos riscos</li>\n    <li>Avaliação da exposição</li>\n    <li>Medidas de controle</li>\n    <li>Sistemas de proteção contra quedas</li>\n</ul>\n<h3>Permissão de Trabalho (PT)</h3>\n<p>Documento escrito que autoriza a realização do trabalho em altura após verificação dos requisitos.</p>', '', '', '', 25, 1, 1, '2026-03-07 22:28:37.286754', 11);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (23, 'Cinturão de Segurança Tipo Paraquedista', 'Inspeção, ajuste e uso correto do cinturão.', 1, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 20, 1, 1, '2026-03-07 22:28:37.325342', 12);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (24, 'Linhas de Vida e Pontos de Ancoragem', 'Instalação e verificação de sistemas antiqueda.', 2, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 22, 1, 1, '2026-03-07 22:28:37.344168', 12);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (25, 'Plano de Emergência e Resgate', 'Elaboração e execução do plano de resgate para trabalho em altura.', 1, 'video_externo', '', '', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '', 25, 1, 1, '2026-03-07 22:28:37.382701', 13);
INSERT INTO `treinamentos_aulaead` (`id`, `titulo`, `descricao`, `ordem`, `tipo_conteudo`, `conteudo_texto`, `arquivo_video`, `url_video_externo`, `arquivo_pdf`, `duracao_estimada_min`, `obrigatoria`, `ativo`, `criado_em`, `modulo_id`) VALUES (26, 'Cores da Coleta Seletiva', '', 2, 'texto', '<h3>Cores da Coleta Seletiva (CONAMA 275/2001)</h3>\n<table class=\'table table-bordered\'>\n<thead><tr><th>Cor</th><th>Material</th></tr></thead>\n<tbody>\n<tr><td><span style="color:#2196F3;font-weight:bold;">&#9632;</span> Azul</td><td>Papel/Papelao</td></tr>\n<tr><td><span style="color:#F44336;font-weight:bold;">&#9632;</span> Vermelho</td><td>Plastico</td></tr>\n<tr><td><span style="color:#4CAF50;font-weight:bold;">&#9632;</span> Verde</td><td>Vidro</td></tr>\n<tr><td><span style="color:#FFEB3B;font-weight:bold;">&#9632;</span> Amarelo</td><td>Metal</td></tr>\n<tr><td><span style="color:#795548;font-weight:bold;">&#9632;</span> Marrom</td><td>Organico</td></tr>\n<tr><td><span style="color:#000000;font-weight:bold;">&#9632;</span> Preto</td><td>Madeira</td></tr>\n<tr><td><span style="color:#CCCCCC;font-weight:bold;">&#9632;</span> Branco</td><td>Residuos de Saude</td></tr>\n<tr><td><span style="color:#FF9800;font-weight:bold;">&#9632;</span> Laranja</td><td>Residuos Perigosos</td></tr>\n<tr><td><span style="color:#9C27B0;font-weight:bold;">&#9632;</span> Roxo</td><td>Residuos Radioativos</td></tr>\n<tr><td><span style="color:#9E9E9E;font-weight:bold;">&#9632;</span> Cinza</td><td>Nao Reciclavel / Misturado</td></tr>\n</tbody></table>', '', '', '', 15, 1, 1, '2026-03-07 22:37:26.910259', 10);
