INSERT INTO `treinamentos_cursoead` (`id`, `titulo`, `slug`, `descricao`, `descricao_curta`, `imagem_capa`, `nivel`, `carga_horaria_total`, `nota_minima`, `max_tentativas_avaliacao`, `percentual_minimo_assistido`, `instrutor_nome`, `instrutor_qualificacao`, `status`, `destaque`, `publicado_em`, `criado_em`, `atualizado_em`, `criado_por_id`, `filial_id`, `tipo_curso_id`) VALUES (2, 'NR-5 — CIPA: Comissão Interna de Prevenção de Acidentes', 'nr-5-cipa-comissao-interna-de-prevencao-de-acidentes', 'Curso completo sobre a Comissão Interna de Prevenção de Acidentes e de Assédio (CIPA). Aborda a legislação vigente, atribuições dos membros, processo eleitoral, mapa de riscos, investigação de acidentes e plano de ação. Essencial para cipeiros titulares e suplentes.', 'Formação completa para membros da CIPA conforme NR-5 atualizada.', '', 'basico', '20.0', '7.0', 3, 80, 'Eng. Carlos Alberto Silva', 'Engenheiro de Segurança do Trabalho — CREA 123456/SP', 'publicado', 1, '2026-03-07 22:22:24.578343', '2026-03-07 22:22:24.578967', '2026-03-07 22:22:24.578990', 1, 1, 7);
INSERT INTO `treinamentos_cursoead` (`id`, `titulo`, `slug`, `descricao`, `descricao_curta`, `imagem_capa`, `nivel`, `carga_horaria_total`, `nota_minima`, `max_tentativas_avaliacao`, `percentual_minimo_assistido`, `instrutor_nome`, `instrutor_qualificacao`, `status`, `destaque`, `publicado_em`, `criado_em`, `atualizado_em`, `criado_por_id`, `filial_id`, `tipo_curso_id`) VALUES (3, 'NR-6 — Equipamentos de Proteção Individual (EPI)', 'nr-6-equipamentos-de-protecao-individual-epi', 'Curso sobre a correta seleção, uso, guarda e conservação dos Equipamentos de Proteção Individual. Aborda responsabilidades do empregador e empregado, Certificado de Aprovação (CA), tipos de EPI por risco e a fiscalização do uso.', 'Aprenda sobre seleção, uso e conservação de EPIs conforme NR-6.', '', 'basico', '8.0', '7.0', 3, 80, 'Téc. Ana Paula Oliveira', 'Técnica de Segurança do Trabalho — Reg. MTE 54321', 'publicado', 1, '2026-03-07 22:22:25.793106', '2026-03-07 22:22:25.793570', '2026-03-07 22:22:25.793589', 1, 1, 7);
INSERT INTO `treinamentos_cursoead` (`id`, `titulo`, `slug`, `descricao`, `descricao_curta`, `imagem_capa`, `nivel`, `carga_horaria_total`, `nota_minima`, `max_tentativas_avaliacao`, `percentual_minimo_assistido`, `instrutor_nome`, `instrutor_qualificacao`, `status`, `destaque`, `publicado_em`, `criado_em`, `atualizado_em`, `criado_por_id`, `filial_id`, `tipo_curso_id`) VALUES (4, 'Ergonomia no Trabalho — NR-17', 'ergonomia-no-trabalho-nr-17', 'Treinamento sobre ergonomia aplicada ao ambiente de trabalho. Aborda postura, mobiliário, iluminação, conforto térmico e organização do trabalho. Essencial para prevenção de LER/DORT.', 'Prevenção de LER/DORT e adequação ergonômica do posto de trabalho.', '', 'intermediario', '12.0', '7.0', 2, 75, 'Dra. Mariana Costa', 'Fisioterapeuta do Trabalho — CREFITO 98765', 'publicado', 0, '2026-03-07 22:22:26.466378', '2026-03-07 22:22:26.466827', '2026-03-07 22:22:26.466855', 1, 1, 8);
INSERT INTO `treinamentos_cursoead` (`id`, `titulo`, `slug`, `descricao`, `descricao_curta`, `imagem_capa`, `nivel`, `carga_horaria_total`, `nota_minima`, `max_tentativas_avaliacao`, `percentual_minimo_assistido`, `instrutor_nome`, `instrutor_qualificacao`, `status`, `destaque`, `publicado_em`, `criado_em`, `atualizado_em`, `criado_por_id`, `filial_id`, `tipo_curso_id`) VALUES (6, 'Gestão de Resíduos Sólidos', 'gestao-de-residuos-solidos', 'Curso sobre gerenciamento de resíduos sólidos no ambiente corporativo. Aborda classificação de resíduos, coleta seletiva, logística reversa, Política Nacional de Resíduos Sólidos e boas práticas ambientais.', 'Gerenciamento correto de resíduos sólidos e coleta seletiva.', '', 'basico', '6.0', '6.0', 3, 70, 'Eng. Roberto Mendes', 'Engenheiro Ambiental — CREA 789012/MG', 'publicado', 0, '2026-03-07 22:25:49.695318', '2026-03-07 22:25:49.695523', '2026-03-07 22:25:49.695530', 1, 1, 9);
INSERT INTO `treinamentos_cursoead` (`id`, `titulo`, `slug`, `descricao`, `descricao_curta`, `imagem_capa`, `nivel`, `carga_horaria_total`, `nota_minima`, `max_tentativas_avaliacao`, `percentual_minimo_assistido`, `instrutor_nome`, `instrutor_qualificacao`, `status`, `destaque`, `publicado_em`, `criado_em`, `atualizado_em`, `criado_por_id`, `filial_id`, `tipo_curso_id`) VALUES (7, 'Trabalho em Altura — NR-35', 'trabalho-em-altura-nr-35', 'Capacitação para trabalho em altura conforme NR-35. Aborda planejamento, sistemas de proteção contra quedas, análise de risco, permissão de trabalho e procedimentos de emergência e resgate.', 'Capacitação obrigatória para trabalho acima de 2 metros.', '', 'avancado', '16.0', '8.0', 2, 90, 'Eng. Carlos Alberto Silva', 'Engenheiro de Segurança do Trabalho — CREA 123456/SP', 'publicado', 1, '2026-03-07 22:28:37.227719', '2026-03-07 22:28:37.228175', '2026-03-07 22:28:37.228193', 1, 1, 7);
