INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (1, 'Qual é o principal objetivo da CIPA?', 1, '1.0', 'A CIPA tem como objetivo a prevenção de acidentes e doenças do trabalho.', 1, 1);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (2, 'Com que frequência devem ocorrer as reuniões ordinárias da CIPA?', 2, '1.0', 'As reuniões ordinárias devem ser realizadas mensalmente.', 1, 1);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (3, 'Qual documento deve ser elaborado após cada reunião da CIPA?', 3, '1.0', 'É obrigatória a lavratura de ata após cada reunião da CIPA.', 1, 1);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (4, 'Quantos dias antes do término do mandato deve ser convocada a eleição da CIPA?', 4, '1.0', 'A convocação deve ser feita com no mínimo 60 dias de antecedência.', 1, 1);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (5, 'O que é o Mapa de Riscos?', 5, '1.0', 'O Mapa de Riscos é uma representação gráfica dos riscos existentes nos ambientes de trabalho.', 1, 1);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (6, 'Qual a sigla do evento de prevenção que a CIPA deve promover anualmente?', 6, '1.0', 'SIPAT — Semana Interna de Prevenção de Acidentes do Trabalho.', 1, 1);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (7, 'Quem pode votar na eleição da CIPA?', 7, '1.0', 'Todos os empregados do estabelecimento têm direito a voto.', 1, 1);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (8, 'Qual NR regulamenta a CIPA?', 8, '1.0', 'A NR-5 é a norma regulamentadora que trata da CIPA.', 1, 1);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (9, 'O mandato dos membros eleitos da CIPA tem duração de:', 9, '1.0', 'O mandato tem duração de 1 ano, sendo permitida uma reeleição.', 1, 1);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (10, 'Em caso de acidente grave, qual tipo de reunião da CIPA deve ser convocada?', 10, '1.0', 'Reunião extraordinária deve ser convocada em caso de acidente grave ou fatal.', 1, 1);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (11, 'O que significa a sigla CA em relação aos EPIs?', 1, '1.0', 'CA = Certificado de Aprovação, emitido pelo MTE.', 1, 2);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (12, 'De quem é a responsabilidade de fornecer EPI gratuitamente ao trabalhador?', 2, '1.0', 'A NR-6 determina que o empregador é obrigado a fornecer EPI gratuitamente.', 1, 2);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (13, 'Qual NR regulamenta os Equipamentos de Proteção Individual?', 3, '1.0', 'A NR-6 regulamenta especificamente os EPIs.', 1, 2);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (14, 'Qual a validade máxima de um Certificado de Aprovação (CA)?', 4, '1.0', 'O CA tem validade máxima de 5 anos.', 1, 2);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (15, 'O trabalhador que se recusa a usar EPI pode sofrer:', 5, '1.0', 'A recusa injustificada é ato faltoso, podendo resultar em advertência e até justa causa.', 1, 2);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (16, 'Qual NR regulamenta a Ergonomia no trabalho?', 1, '1.0', 'A NR-17 é a norma regulamentadora sobre Ergonomia.', 1, 3);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (17, 'O que significa a sigla LER?', 2, '1.0', 'LER = Lesão por Esforço Repetitivo.', 1, 3);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (18, 'Qual a altura ideal do monitor em relação aos olhos?', 3, '1.0', 'O topo do monitor deve ficar na altura dos olhos ou ligeiramente abaixo.', 1, 3);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (19, 'De quanto em quanto tempo é recomendado fazer pausas em trabalho com computador?', 4, '1.0', 'Recomenda-se pausas de 10 minutos a cada 50 minutos de trabalho contínuo.', 1, 3);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (20, 'O que é Ginástica Laboral?', 5, '1.0', 'É a prática de exercícios físicos no ambiente de trabalho para prevenção de doenças ocupacionais.', 1, 3);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (21, 'A partir de qual altura o trabalho é considerado trabalho em altura pela NR-35?', 1, '1.0', 'A NR-35 considera trabalho em altura toda atividade acima de 2 metros.', 1, 4);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (22, 'Qual tipo de cinturão é obrigatório para trabalho em altura?', 2, '1.0', 'O cinturão tipo paraquedista é o obrigatório para trabalho em altura.', 1, 4);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (23, 'Qual documento autoriza a realização do trabalho em altura?', 3, '1.0', 'A Permissão de Trabalho (PT) é o documento que autoriza a atividade.', 1, 4);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (24, 'O que deve ser feito ANTES de qualquer trabalho em altura?', 4, '1.0', 'A Análise de Risco é obrigatória antes de qualquer trabalho em altura.', 1, 4);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (25, 'A capacitação para trabalho em altura tem validade de:', 5, '1.0', 'O treinamento periódico deve ser realizado a cada 2 anos.', 1, 4);
INSERT INTO `treinamentos_questaoead` (`id`, `enunciado`, `ordem`, `peso`, `explicacao`, `ativo`, `avaliacao_id`) VALUES (26, 'Qual resolucao do CONAMA define as cores para coleta seletiva?', 1, '1.0', '', 1, 5);
